var documenterSearchIndex = {"docs":
[{"location":"user/composite_dsl/#composite_dsl_user","page":"Composite DSL","title":"Composite DSL","text":"","category":"section"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"The composite DSL builds CompositeAlgorithm and Routine values from a block syntax. It is a constructor shorthand: entries still become normal algorithms, states, routes, shares, and schedules.","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"Use @CompositeAlgorithm when child entries should run on interval schedules. Use @Routine when child entries should run sequentially with repeat counts.","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"algo = @CompositeAlgorithm begin\n    @state seed = 3\n    @alias source = SourceAlgo\n\n    produced, passthrough = source(seed = seed)\n    doubled = @interval 10 double(produced)\n    Sink(value = doubled)\nend","category":"page"},{"location":"user/composite_dsl/#Inline-State","page":"Composite DSL","title":"Inline State","text":"","category":"section"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"Declare local state with @state.","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"algo = @Routine begin\n    @state equilibrium_state\n    @state clamping_beta = 0.0\n    @state buffers = Float64[]\n\n    Step(value = clamping_beta)\nend","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"Fields without defaults are required during init. Fields with defaults are rebuilt for each process initialization.","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"You can also give the inline state an explicit key:","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"algo = @CompositeAlgorithm begin\n    @state learning_state begin\n        loss = 0.0\n        buffer = Float64[]\n    end\n\n    Logger(value = loss)\nend","category":"page"},{"location":"user/composite_dsl/#Runtime-Inputs","page":"Composite DSL","title":"Runtime Inputs","text":"","category":"section"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"Declare per-run values with @input.","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"algo = @CompositeAlgorithm begin\n    @state energy = 0.0\n    @input temperature::AbstractFloat\n    @input sweep = 1\n\n    accepted = metropolis_step(energy, temperature; sweep = sweep)\nend","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"Runtime inputs are supplied to run as keyword arguments:","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"p = Process(algo; repeats = 100)\nrun(p; temperature = 2.0)","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"They are validated once before the loop starts and are visible during the run through the transient ProcessContext._input field. They are not stored in the initialized loop algorithm or finished process context after the run.","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"Forms:","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"@input required_name\n@input typed_name::AbstractFloat\n@input defaulted_name = 1","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"Use runtime @input for scalar parameters or small values that can change from run to run. Use @state or Init(...) for persistent buffers and setup data.","category":"page"},{"location":"user/composite_dsl/#Aliases","page":"Composite DSL","title":"Aliases","text":"","category":"section"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"Use @alias to name an algorithm constructor or value for later DSL entries.","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"algo = @Routine begin\n    @alias dynamics = Metropolis(model)\n    @alias capture = Capturer()\n\n    state = dynamics()\n    capture(value = state)\nend","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"Aliases are macro-time names. They affect later uses of the alias in the DSL; they are not runtime variables.","category":"page"},{"location":"user/composite_dsl/#Function-Calls","page":"Composite DSL","title":"Function Calls","text":"","category":"section"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"Plain Julia function calls are wrapped in a small process algorithm.","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"algo = @Routine begin\n    @state x = 2\n    y = sqrt(x)\n    z = scale_value(y; scale = 3)\nend","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"Known DSL names such as x and y are routed from context. Other Julia values are captured into the wrapper.","category":"page"},{"location":"user/composite_dsl/#Algorithm-Routes","page":"Composite DSL","title":"Algorithm Routes","text":"","category":"section"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"Keyword arguments to process algorithms are route declarations.","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"algo = @CompositeAlgorithm begin\n    @state seed = 3\n    produced = Source(seed = seed)\n    Sink(value = produced)\nend","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"Sink(value = produced) routes produced into the target as value.","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"Process algorithms created with @ProcessAlgorithm can also use direct positional syntax when their positional argument names are known:","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"algo = @Routine begin\n    @state value = 1\n    MyGeneratedAlgo(value)\nend","category":"page"},{"location":"user/composite_dsl/#Transform-Routes","page":"Composite DSL","title":"Transform Routes","text":"","category":"section"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"Use explicit @transform(f, source) when a routed value should be transformed before it reaches the target.","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"algo = @Routine begin\n    @state clamping_beta = 2.0\n    SetBeta(value = @transform(x -> -x, clamping_beta))\nend","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"The source can be a normal DSL symbol or an owned-field reference:","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"algo = @CompositeAlgorithm begin\n    @context c = nested()\n    result = identity(@transform(x -> x + 1, c.capture.value))\nend","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"Transforms are route syntax, not general Julia expression syntax. Write @transform(x -> -x, clamping_beta), not -clamping_beta, when the value must come from the process context.","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"Use an explicit @route statement when a transformed route also needs writeback through a reverse transform:","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"algo = @CompositeAlgorithm begin\n    @alias source = SourceAlgo\n    @alias target = TargetAlgo\n\n    source()\n    target()\n\n    @route source.value => target.input transform = x -> 2x reverse_transform = y -> y / 2\nend","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"Here target reads input through the forward transform. If it returns (; input = new_input), the source field value is updated through reverse_transform.","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"@transform(f, source) is read-transform syntax for call arguments. Reverse writeback uses @route ... reverse_transform = g.","category":"page"},{"location":"user/composite_dsl/#Ref-and-Indexed-Reads","page":"Composite DSL","title":"Ref and Indexed Reads","text":"","category":"section"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"Indexed reads from context values are routed as transform routes.","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"algo = @CompositeAlgorithm begin\n    @state clamping_beta = Ref(2.0)\n    Sink(value = clamping_beta[])\nend","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"This routes clamping_beta and applies getindex before the target sees it. The same shape works with indexes and ranges:","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"algo = @Routine begin\n    @state buffer = [1, 2, 3]\n    first_value = identity(buffer[1])\n    tail = identity(buffer[2:3])\nend","category":"page"},{"location":"user/composite_dsl/#Direct-State-Writes","page":"Composite DSL","title":"Direct State Writes","text":"","category":"section"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"Assigning a captured Julia value to an inline state field lowers to a ContextWrite widget.","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"somevar = 3\n\nalgo = @Routine begin\n    @state clamping_beta = 1.0\n    clamping_beta = somevar\nend","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"The assignment captures somevar when the loop algorithm is constructed. At step time, the value is converted to the current context field type when the field already exists.","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"If the right-hand side is a context value, route it explicitly through normal DSL syntax:","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"algo = @Routine begin\n    @state source = 2.0\n    @state target = 0.0\n    target = source\nend","category":"page"},{"location":"user/composite_dsl/#Indexed-Mutation","page":"Composite DSL","title":"Indexed Mutation","text":"","category":"section"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"Use normal indexed assignment to mutate buffers stored in context.","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"algo = @Routine begin\n    @state buffer = [0, 0, 0]\n\n    buffer[1] = 2\n    buffer[2:3] = [4, 5]\nend","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"This lowers to a wrapped setindex! call. The buffer itself is routed from the context, then mutated in place.","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"Indexes may be literals, variables captured from the surrounding Julia scope, or ranges:","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"idx = 2\n\nalgo = @Routine begin\n    @state buffer = [0, 0, 0]\n    buffer[idx] = 9\nend","category":"page"},{"location":"user/composite_dsl/#Broadcast-Mutation","page":"Composite DSL","title":"Broadcast Mutation","text":"","category":"section"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"Broadcast assignment is also supported for context buffers.","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"replacement = [7, 8]\n\nalgo = @Routine begin\n    @state buffer = [0, 0, 0]\n\n    buffer .= 1\n    buffer[2:3] .= replacement\nend","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"Whole-buffer broadcast lowers to context_broadcast!(buffer, value). Indexed broadcast lowers through view(buffer, inds...), so range writes mutate the original buffer rather than a copied slice.","category":"page"},{"location":"user/composite_dsl/#Owned-Field-Reads","page":"Composite DSL","title":"Owned Field Reads","text":"","category":"section"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"Use dotted references to read fields owned by aliased algorithms or nested contexts.","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"algo = @Routine begin\n    @alias dynamics = Dynamics()\n\n    seen = Sink(value = dynamics.state)\n    state = dynamics()\nend","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"The special binding form:","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"state = dynamics.state","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"exposes the owned field under the plain DSL name state for later statements.","category":"page"},{"location":"user/composite_dsl/#Owned-Field-Writes","page":"Composite DSL","title":"Owned Field Writes","text":"","category":"section"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"You can assign to an owned field target.","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"nudged = @Routine begin\n    @state nudged_beta = 0.0\n    Step(beta = nudged_beta)\nend\n\nalgo = @CompositeAlgorithm begin\n    @state clamping_beta = Ref(2.0)\n    @alias nudged = nudged\n\n    nudged.nudged_beta = clamping_beta[]\n    nudged()\nend","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"This creates a ContextWrite entry and routes the assigned value into it. For a nested routine's inline state, the write targets the nested state field through the normal route and merge machinery.","category":"page"},{"location":"user/composite_dsl/#Explicit-State-Sharing","page":"Composite DSL","title":"Explicit State Sharing","text":"","category":"section"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"Nested DSL blocks can independently declare the same state field. That remains compatible, but the merge now warns unless the parent documents the intended sharing.","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"Use @bind when the parent block owns, defaults, or requires the shared state and a child block should use that same slot.","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"@bind buffers => f.buffers","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"This says: the current block's buffers state slot and child context f's inline buffers state slot are intentionally the same resource.","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"forward = @Routine begin\n    @state buffers\n    buffers = fill_forward!(buffers)\nend\n\nnudged = @Routine begin\n    @state buffers\n    buffers = read_nudged!(buffers)\nend\n\nalgo = @CompositeAlgorithm begin\n    @state buffers = make_buffers()\n\n    @context f = forward()\n    @context n = nudged()\n\n    @bind buffers => f.buffers\n    @bind buffers => n.buffers\nend","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"In this example, algo creates the buffer with make_buffers(). Both child routines declare @state buffers because each routine is still a reusable building block with a local contract, but the parent explicitly binds both child contracts to the parent-owned state slot.","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"Use @merge when child blocks should share with each other and the parent does not need to declare a separate state slot:","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"@merge f.buffers, n.buffers","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"This says: child context f's inline buffers slot and child context n's inline buffers slot are intentionally the same resource.","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"algo = @CompositeAlgorithm begin\n    @context f = forward()\n    @context n = nudged()\n\n    @merge f.buffers, n.buffers\nend","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"If neither child supplies a default, the merged field remains required:","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"algo = @CompositeAlgorithm begin\n    @context f = forward()\n    @context n = nudged()\n\n    @merge f.buffers, n.buffers\nend\n\nresolved = resolve(algo)\ninitialized = init(resolved, Init(:_state; buffers = make_buffers()))","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"If one side has a default and the other side is required, the default satisfies the merged slot:","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"forward_with_default = @Routine begin\n    @state buffers = make_buffers()\n    buffers = fill_forward!(buffers)\nend\n\nalgo = @CompositeAlgorithm begin\n    @context f = forward_with_default()\n    @context n = nudged()\n\n    @merge f.buffers, n.buffers\nend","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"If multiple merged slots provide defaults for the same field, construction still continues but warns because the later default wins. Prefer a single parent default with @bind when ownership is clear.","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"Selectors are written against @context aliases and must appear after the context has been declared:","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"algo = @CompositeAlgorithm begin\n    @context f = forward()\n    @context n = nudged()\n\n    @merge f.buffers, n.buffers\nend","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"f.buffers is transparent syntax for the nested inline state field f._state.buffers; both forms are accepted:","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"@merge f._state.buffers, n.buffers\n@bind buffers => f._state.buffers","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"Use @bind for parent-to-child sharing. Use @merge for peer child-to-child sharing. Without either declaration, overlapping child state fields are still merged for compatibility, but the DSL warns with paths such as f.buffers <=> n.buffers and suggests an explicit @bind or @merge.","category":"page"},{"location":"user/composite_dsl/#Context-Aliases","page":"Composite DSL","title":"Context Aliases","text":"","category":"section"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"Use @context when later statements need to refer to the subcontext produced by a nested DSL entry.","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"plus = @Routine begin\n    @alias capture = Capturer()\n    capture()\nend\n\nalgo = @CompositeAlgorithm begin\n    @context c1 = plus()\n    result = identity(c1.capture.value)\nend","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"@context is only a macro-time reference. The wrapped entry still runs as the right-hand side expression says.","category":"page"},{"location":"user/composite_dsl/#Full-Context-Shares","page":"Composite DSL","title":"Full-Context Shares","text":"","category":"section"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"Use @all(source) or @all(source...) in an algorithm call to lower to a normal Share.","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"algo = @CompositeAlgorithm begin\n    @alias source = Source\n    source()\n    Consumer(@all(source...))\nend","category":"page"},{"location":"user/composite_dsl/#Scheduling","page":"Composite DSL","title":"Scheduling","text":"","category":"section"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"Inside @CompositeAlgorithm, use @interval or @every on the right-hand side of an entry.","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"algo = @CompositeAlgorithm begin\n    @state value = 1\n    sampled = @interval 10 Sample(value)\nend","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"Inside @Routine, use @repeat.","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"routine = @Routine begin\n    @state value = 1\n    value = @repeat 5 Step(value = value)\nend","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"@repeat also accepts the normal lifetime constructors. When a lifetime selector is written as a DSL variable, the DSL resolves it to the corresponding Var(...) selector:","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"routine = @Routine begin\n    count = @repeat Until(x -> x >= 100, count) Counter()\nend","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"Supported forms are Repeat(n), Indefinite(), Until(condition, selector), RepeatOrUntil(condition, n, selector), AtLeast(condition, n, selector), and AtLeastAtMost(condition, min, max, selector).","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"For repeated sub-blocks:","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"algo = @CompositeAlgorithm begin\n    @state value = 1\n\n    result = @repeat 3 begin\n        value = Step(value = value)\n        value = Step(value = value)\n    end\nend","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"Write schedules on the right-hand side:","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"value = @interval 10 Step(value = value)","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"not:","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"@interval 10 value = Step(value = value)","category":"page"},{"location":"user/composite_dsl/#Conditional-Entries","page":"Composite DSL","title":"Conditional Entries","text":"","category":"section"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"Use @include_if to include or skip entries when constructing the loop algorithm.","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"algo = @CompositeAlgorithm begin\n    @state seed = 3\n    @include_if include_source produced = Source(seed = seed)\n    Sink(value = seed)\nend","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"The condition is evaluated at construction time. Skipped entries are not registered and do not contribute routes, shares, or schedules.","category":"page"},{"location":"user/composite_dsl/#Final-Post-Processing","page":"Composite DSL","title":"Final Post-Processing","text":"","category":"section"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"Use one root-level @finally to wrap the outer algorithm with a final post-processing function.","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"algo = @CompositeAlgorithm begin\n    @state seed = 8\n    Sink(value = seed)\n    @finally summarize_context\nend","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"@finally is only valid at the outer DSL block level.","category":"page"},{"location":"user/interactive/#interactive_user","page":"Interactive Contexts","title":"Interactive Contexts","text":"","category":"section"},{"location":"user/interactive/","page":"Interactive Contexts","title":"Interactive Contexts","text":"ContextExchange gives external code a polled read/write handle to selected process variables.","category":"page"},{"location":"user/interactive/#Selectors","page":"Interactive Contexts","title":"Selectors","text":"","category":"section"},{"location":"user/interactive/","page":"Interactive Contexts","title":"Interactive Contexts","text":"Add a ContextExchange child and pass its Var selectors as init-only vars:","category":"page"},{"location":"user/interactive/","page":"Interactive Contexts","title":"Interactive Contexts","text":"algo = resolve(CompositeAlgorithm(\n    :target => MyAlgo(),\n    :_exchange => ContextExchange(),\n    (1, 20),\n))\n\ncontext = Processes.context(init(\n    algo,\n    Init(:_exchange; vars = (Var(:target, :value), Var(:target, :seen))),\n))","category":"page"},{"location":"user/interactive/","page":"Interactive Contexts","title":"Interactive Contexts","text":"Selectors are resolved during initcontext, when the registry and concrete state layout are available. The resolved paths are stored in the exchange state type, and ContextExchange uses a custom _step! instead of route/wiring machinery.","category":"page"},{"location":"user/interactive/","page":"Interactive Contexts","title":"Interactive Contexts","text":"For a different external name, use a pair:","category":"page"},{"location":"user/interactive/","page":"Interactive Contexts","title":"Interactive Contexts","text":"Init(:_exchange; vars = (:display => Var(:target, :value),))","category":"page"},{"location":"user/interactive/","page":"Interactive Contexts","title":"Interactive Contexts","text":"Type selectors are also supported when they resolve uniquely:","category":"page"},{"location":"user/interactive/","page":"Interactive Contexts","title":"Interactive Contexts","text":"Init(:_exchange; vars = (:display => Var(MyAlgo, :value),))","category":"page"},{"location":"user/interactive/#Polling-And-Writes","page":"Interactive Contexts","title":"Polling And Writes","text":"","category":"section"},{"location":"user/interactive/","page":"Interactive Contexts","title":"Interactive Contexts","text":"External code reads and writes exchange-local names:","category":"page"},{"location":"user/interactive/","page":"Interactive Contexts","title":"Interactive Contexts","text":"ref = view(context, :value)\nref[]          # last published value, initialized from the target field\nref[] = 4      # queued write","category":"page"},{"location":"user/interactive/","page":"Interactive Contexts","title":"Interactive Contexts","text":"The next due exchange step converts pending writes to the current target field type and writes directly into the resolved subcontext. Current values are also published to the ref slots on due exchange steps.","category":"page"},{"location":"user/interactive/","page":"Interactive Contexts","title":"Interactive Contexts","text":"Programmatic writes use the same names:","category":"page"},{"location":"user/interactive/","page":"Interactive Contexts","title":"Interactive Contexts","text":"interact!(context, :value => 5)\ninteract!(process, :value => 5)","category":"page"},{"location":"user/interactive/","page":"Interactive Contexts","title":"Interactive Contexts","text":"Default lookup expects one ContextExchange in the process. If there are multiple exchanges, pass the exchange key explicitly.","category":"page"},{"location":"user/interactive/#Scheduling","page":"Interactive Contexts","title":"Scheduling","text":"","category":"section"},{"location":"user/interactive/","page":"Interactive Contexts","title":"Interactive Contexts","text":"The outer loop schedule still controls how often the exchange child is called:","category":"page"},{"location":"user/interactive/","page":"Interactive Contexts","title":"Interactive Contexts","text":"CompositeAlgorithm(target, :_exchange => ContextExchange(), (1, 20))\nProcesses.context(init(algo, Init(:_exchange; vars = (Var(:target, :value),))))","category":"page"},{"location":"user/interactive/","page":"Interactive Contexts","title":"Interactive Contexts","text":"The exchange also supports a wall-clock gate:","category":"page"},{"location":"user/interactive/","page":"Interactive Contexts","title":"Interactive Contexts","text":"ContextExchange(; period = 0.05)\nInit(:_exchange; vars = (Var(:target, :value),))","category":"page"},{"location":"user/interactive/","page":"Interactive Contexts","title":"Interactive Contexts","text":"If the exchange is called before period seconds have elapsed, it returns without reading selected variables or applying pending writes.","category":"page"},{"location":"user/interactive/#Complete-Example","page":"Interactive Contexts","title":"Complete Example","text":"","category":"section"},{"location":"user/interactive/","page":"Interactive Contexts","title":"Interactive Contexts","text":"using Processes\n\nstruct InteractiveTarget <: ProcessAlgorithm end\n\nfunction Processes.init(::InteractiveTarget, context)\n    return (; value = 1.0)\nend\n\nfunction Processes.step!(::InteractiveTarget, context)\n    return (;)\nend\n\nalgo = resolve(CompositeAlgorithm(\n    :target => InteractiveTarget(),\n    :_exchange => ContextExchange(),\n    (1, 1),\n))\n\ncontext = Processes.context(init(\n    algo,\n    Init(:_exchange; vars = (Var(:target, :value),));\n    lifetime = Repeat(3),\n))\nref = view(context, :value)\n\nref[] == 1.0\n\nref[] = 4\ncontext = Processes._step!(algo, context, Processes.Stable())\n\nref[] == 4.0\ncontext.target.value == 4.0","category":"page"},{"location":"user/interactive/","page":"Interactive Contexts","title":"Interactive Contexts","text":"The interactive API is covered in test/ContextExchangeTest.jl.","category":"page"},{"location":"user/copying_and_management/#copying_processes_user","page":"Copying Processes","title":"Copying Processes","text":"","category":"section"},{"location":"user/copying_and_management/","page":"Copying Processes","title":"Copying Processes","text":"This page documents the process-copy helpers.","category":"page"},{"location":"user/copying_and_management/","page":"Copying Processes","title":"Copying Processes","text":"A process copy is rebuilt from saved construction data, not by copying the live context directly. This matters when a context was initialized from external storage, buffers, or data views.","category":"page"},{"location":"user/copying_and_management/","page":"Copying Processes","title":"Copying Processes","text":"If you want to run many independent jobs through reusable processes on Julia threads, see Threaded Process Managers.","category":"page"},{"location":"user/copying_and_management/#Why-Copy-Instead-of-deepcopy","page":"Copying Processes","title":"Why Copy Instead of deepcopy","text":"","category":"section"},{"location":"user/copying_and_management/","page":"Copying Processes","title":"Copying Processes","text":"Process contexts are often built from Init(...) values that point at external storage, buffers, or data views. A raw deepcopy of the live context can therefore copy the wrong thing or preserve sharing that should be rebuilt per process.","category":"page"},{"location":"user/copying_and_management/","page":"Copying Processes","title":"Copying Processes","text":"The copying helpers work from the initialized loop algorithm and the normal lifecycle init pipeline instead:","category":"page"},{"location":"user/copying_and_management/","page":"Copying Processes","title":"Copying Processes","text":"copy the stored loop algorithm recipe,\nreplace selected inputs and overrides,\ninitialize a fresh context for each copy.","category":"page"},{"location":"user/copying_and_management/","page":"Copying Processes","title":"Copying Processes","text":"The saved recipe is the initialized loop algorithm: it stores the resolved algorithm, persistent context, and replayable Init/Override specs.","category":"page"},{"location":"user/copying_and_management/#Copy-APIs","page":"Copying Processes","title":"Copy APIs","text":"","category":"section"},{"location":"user/copying_and_management/#Processes.copyinputs","page":"Copying Processes","title":"Processes.copyinputs","text":"copyinputs(process_or_la)\n\nReturn the stored Init specs for an initialized process or loop algorithm.\n\n\n\n\n\n","category":"function"},{"location":"user/copying_and_management/#Processes.copyoverrides","page":"Copying Processes","title":"Processes.copyoverrides","text":"copyoverrides(process_or_la)\n\nReturn the stored Override specs for an initialized process or loop algorithm.\n\n\n\n\n\n","category":"function"},{"location":"user/copying_and_management/#Processes.copyprocess","page":"Copying Processes","title":"Processes.copyprocess","text":"copyprocess(p::Process, Init(...), Override(...); kwargs...)\n\nBuild a new process from the stored initialized loop algorithm recipe. Extra init/override specs are merged by init.\n\n\n\n\n\n","category":"function"},{"location":"user/copying_and_management/#Typical-Copy-Pattern","page":"Copying Processes","title":"Typical Copy Pattern","text":"","category":"section"},{"location":"user/copying_and_management/","page":"Copying Processes","title":"Copying Processes","text":"template = Process(\n    MyAlgo,\n    Init(MyAlgo; start = 0, buffer = Int[]),\n    Override(MyAlgo; delta = 2);\n    repeats = 10,\n)\n\np = copyprocess(\n    template,\n    Init(MyAlgo; start = 100, buffer = Int[]),\n)\n\nrun(p)\nwait(p)\nclose(p)","category":"page"},{"location":"user/copying_and_management/","page":"Copying Processes","title":"Copying Processes","text":"If the context needs custom rebuilding logic, provide a fully prepared context = ... directly.","category":"page"},{"location":"user/contexts/#contexts_user","page":"Contexts and Indexing","title":"Contexts and Indexing","text":"","category":"section"},{"location":"user/contexts/#What-You-Receive-in-init/step!/cleanup","page":"Contexts and Indexing","title":"What You Receive in init/step!/cleanup","text":"","category":"section"},{"location":"user/contexts/","page":"Contexts and Indexing","title":"Contexts and Indexing","text":"The full runtime data object is a ProcessContext.","category":"page"},{"location":"user/contexts/","page":"Contexts and Indexing","title":"Contexts and Indexing","text":"Each registered algorithm or state owns one named part of that context. That part is a SubContext.","category":"page"},{"location":"user/contexts/","page":"Contexts and Indexing","title":"Contexts and Indexing","text":"Entity methods receive a SubContextView, not the raw ProcessContext. A view shows the values that the current entity is allowed to read. Those values can come from its own subcontext, from a Route, from a Share, or from temporary values supplied by the package.","category":"page"},{"location":"user/contexts/","page":"Contexts and Indexing","title":"Contexts and Indexing","text":"That view exposes:","category":"page"},{"location":"user/contexts/","page":"Contexts and Indexing","title":"Contexts and Indexing","text":"local subcontext variables,\nrouted/shared variables,\nglobals via getglobals(context).","category":"page"},{"location":"user/contexts/#Reading-Variables","page":"Contexts and Indexing","title":"Reading Variables","text":"","category":"section"},{"location":"user/contexts/","page":"Contexts and Indexing","title":"Contexts and Indexing","text":"function Processes.step!(::MyAlgo, context)\n    (; state, dt) = context\n    # ...\n    return (;)\nend","category":"page"},{"location":"user/contexts/","page":"Contexts and Indexing","title":"Contexts and Indexing","text":"context.name and destructuring both read from the view.","category":"page"},{"location":"user/contexts/#Writing-Variables","page":"Contexts and Indexing","title":"Writing Variables","text":"","category":"section"},{"location":"user/contexts/","page":"Contexts and Indexing","title":"Contexts and Indexing","text":"Return a NamedTuple from step!/init/cleanup.","category":"page"},{"location":"user/contexts/","page":"Contexts and Indexing","title":"Contexts and Indexing","text":"Existing names update mapped targets.\nNew names are added to local subcontext.\nType changes are rejected once the stable loop is running.","category":"page"},{"location":"user/contexts/","page":"Contexts and Indexing","title":"Contexts and Indexing","text":"If Target sees source_value through a route and returns (; source_value = 2.0), the stored value in the source subcontext is updated. If it returns (; new_local_value = 2.0), that value is added to Target's own subcontext.","category":"page"},{"location":"user/contexts/#Top-Level-Context-Access","page":"Contexts and Indexing","title":"Top-Level Context Access","text":"","category":"section"},{"location":"user/contexts/","page":"Contexts and Indexing","title":"Contexts and Indexing","text":"From a process:","category":"page"},{"location":"user/contexts/","page":"Contexts and Indexing","title":"Contexts and Indexing","text":"ctx = context(p)","category":"page"},{"location":"user/contexts/","page":"Contexts and Indexing","title":"Contexts and Indexing","text":"context(p) returns the stored persistent context. getcontext(p) returns a runtime-flavored context with the process injected into globals.","category":"page"},{"location":"user/contexts/","page":"Contexts and Indexing","title":"Contexts and Indexing","text":"From a context, index by:","category":"page"},{"location":"user/contexts/","page":"Contexts and Indexing","title":"Contexts and Indexing","text":"symbol key: ctx[:Fib_1]\nregistered value/type: ctx[Fib], ctx[Fib()], ctx[my_unique_fib]","category":"page"},{"location":"user/contexts/","page":"Contexts and Indexing","title":"Contexts and Indexing","text":"Object and type lookup use the same identity rules as Input, Override, Route, and Share. See Referencing Algorithms.","category":"page"},{"location":"user/contexts/","page":"Contexts and Indexing","title":"Contexts and Indexing","text":"Related symbol-based lookup also works on resolved loop algorithms and registries:","category":"page"},{"location":"user/contexts/","page":"Contexts and Indexing","title":"Contexts and Indexing","text":"resolved = resolve(CompositeAlgorithm(Fib, Noise, (1, 2)))\nreg = getregistry(resolved)\n\nresolved[:Fib_1]   # same object as resolved.Fib_1\nreg[:Fib_1]        # registered IdentifiableAlgo\nctx[:Fib_1]        # subcontext","category":"page"},{"location":"user/contexts/","page":"Contexts and Indexing","title":"Contexts and Indexing","text":"Use loop-algorithm indexing when you want the registered algorithm or state object, and context indexing when you want its current stored data.","category":"page"},{"location":"user/contexts/#Re-Initializing-One-Subcontext","page":"Contexts and Indexing","title":"Re-Initializing One Subcontext","text":"","category":"section"},{"location":"user/contexts/","page":"Contexts and Indexing","title":"Contexts and Indexing","text":"You can re-run init for one registered algorithm inside an existing context:","category":"page"},{"location":"user/contexts/","page":"Contexts and Indexing","title":"Contexts and Indexing","text":"ctx = initcontext(resolved)\n\nctx = initcontext(ctx, :Fib_1)\nctx = initcontext(ctx, :Fib_1; inputs = (; seed = 123))\nctx = initcontext(ctx, resolved[:Fib_1]; overrides = (; value = 0.0))","category":"page"},{"location":"user/contexts/","page":"Contexts and Indexing","title":"Contexts and Indexing","text":"This updates only the targeted subcontext.","category":"page"},{"location":"user/contexts/","page":"Contexts and Indexing","title":"Contexts and Indexing","text":"inputs are merged into that subcontext before init(...) runs.\noverrides are merged into that subcontext after init(...) returns.","category":"page"},{"location":"user/contexts/#Globals","page":"Contexts and Indexing","title":"Globals","text":"","category":"section"},{"location":"user/contexts/","page":"Contexts and Indexing","title":"Contexts and Indexing","text":"ProcessContext includes a globals field.","category":"page"},{"location":"user/contexts/","page":"Contexts and Indexing","title":"Contexts and Indexing","text":"Common globals:","category":"page"},{"location":"user/contexts/","page":"Contexts and Indexing","title":"Contexts and Indexing","text":"lifetime\nalgo\nprocess (in runtime loop context)","category":"page"},{"location":"user/contexts/","page":"Contexts and Indexing","title":"Contexts and Indexing","text":"Use getglobals(context) inside entity methods when you need them. Globals are process-level values, not values owned by one algorithm.","category":"page"},{"location":"user/contexts/","page":"Contexts and Indexing","title":"Contexts and Indexing","text":"You can also select globals with Var(:name) in APIs like Until(...). See Vars (Var Selectors).","category":"page"},{"location":"user/contexts/","page":"Contexts and Indexing","title":"Contexts and Indexing","text":"For buffered external writes through ContextExchange and ref-like view(context, Var(...)) handles, see Interactive Contexts.","category":"page"},{"location":"user/vars/#vars_user","page":"Vars (Var Selectors)","title":"Vars (Var Selectors)","text":"","category":"section"},{"location":"user/vars/","page":"Vars (Var Selectors)","title":"Vars (Var Selectors)","text":"Var is a small selector object used to say \"read this stored value later\".","category":"page"},{"location":"user/vars/","page":"Vars (Var Selectors)","title":"Vars (Var Selectors)","text":"It is most often used by lifetimes such as Until, where the stop condition needs one value from the current context.","category":"page"},{"location":"user/vars/#Two-Forms","page":"Vars (Var Selectors)","title":"Two Forms","text":"","category":"section"},{"location":"user/vars/#1.-Subcontext-variable","page":"Vars (Var Selectors)","title":"1. Subcontext variable","text":"","category":"section"},{"location":"user/vars/","page":"Vars (Var Selectors)","title":"Vars (Var Selectors)","text":"Var(entity_ref, :name)","category":"page"},{"location":"user/vars/","page":"Vars (Var Selectors)","title":"Vars (Var Selectors)","text":"This reads :name from the subcontext of entity_ref. Use the same entity_ref style you used when building the process: type, saved instance, saved Unique(...) value, or symbol key.","category":"page"},{"location":"user/vars/","page":"Vars (Var Selectors)","title":"Vars (Var Selectors)","text":"Example:","category":"page"},{"location":"user/vars/","page":"Vars (Var Selectors)","title":"Vars (Var Selectors)","text":"counter = Counter()\nVar(counter, :count)","category":"page"},{"location":"user/vars/#2.-Global-variable","page":"Vars (Var Selectors)","title":"2. Global variable","text":"","category":"section"},{"location":"user/vars/","page":"Vars (Var Selectors)","title":"Vars (Var Selectors)","text":"Var(:name)","category":"page"},{"location":"user/vars/","page":"Vars (Var Selectors)","title":"Vars (Var Selectors)","text":"This reads :name from context.globals.","category":"page"},{"location":"user/vars/","page":"Vars (Var Selectors)","title":"Vars (Var Selectors)","text":"So:","category":"page"},{"location":"user/vars/","page":"Vars (Var Selectors)","title":"Vars (Var Selectors)","text":"Var(:process) reads context.globals.process\nVar(:algo) reads context.globals.algo\nVar(:lifetime) reads context.globals.lifetime","category":"page"},{"location":"user/vars/#Common-Use-in-Until","page":"Vars (Var Selectors)","title":"Common Use in Until","text":"","category":"section"},{"location":"user/vars/","page":"Vars (Var Selectors)","title":"Vars (Var Selectors)","text":"Var is commonly used with Until(...) to pick what value the stop condition should inspect.","category":"page"},{"location":"user/vars/","page":"Vars (Var Selectors)","title":"Vars (Var Selectors)","text":"Example with a subcontext variable:","category":"page"},{"location":"user/vars/","page":"Vars (Var Selectors)","title":"Vars (Var Selectors)","text":"counter = Counter()\n\nlifetime = Until(x -> x >= 100, Var(counter, :count))","category":"page"},{"location":"user/vars/","page":"Vars (Var Selectors)","title":"Vars (Var Selectors)","text":"Example with a global variable (process object):","category":"page"},{"location":"user/vars/","page":"Vars (Var Selectors)","title":"Vars (Var Selectors)","text":"lifetime = Until(p -> loopidx(p) >= 10_000, Var(:process))","category":"page"},{"location":"user/vars/","page":"Vars (Var Selectors)","title":"Vars (Var Selectors)","text":"Var(:process) is useful when your stop rule depends on process-level state.","category":"page"},{"location":"user/vars/","page":"Vars (Var Selectors)","title":"Vars (Var Selectors)","text":"In Until/RepeatOrUntil, this function is a stop condition (true => stop, false => continue).","category":"page"},{"location":"user/vars/","page":"Vars (Var Selectors)","title":"Vars (Var Selectors)","text":"Var(...) is also the selector syntax used by interactive refs returned from view(context, Var(...)). See Interactive Contexts.","category":"page"},{"location":"user/inputs_overrides/#inputs_overrides_user","page":"Init, Overrides, and Runtime Inputs","title":"Init, Overrides, and Runtime Inputs","text":"","category":"section"},{"location":"user/inputs_overrides/","page":"Init, Overrides, and Runtime Inputs","title":"Init, Overrides, and Runtime Inputs","text":"Initialization specs and runtime inputs solve different problems.","category":"page"},{"location":"user/inputs_overrides/","page":"Init, Overrides, and Runtime Inputs","title":"Init, Overrides, and Runtime Inputs","text":"Init(...) provides values used while building persistent context.\nOverride(...) force-replaces initialized persistent context values.\nDSL @input declares per-run values supplied as run(...; kwargs...).","category":"page"},{"location":"user/inputs_overrides/","page":"Init, Overrides, and Runtime Inputs","title":"Init, Overrides, and Runtime Inputs","text":"Input(...) is still accepted as a compatibility alias for Init(...).","category":"page"},{"location":"user/inputs_overrides/#Init-and-Override-Specs","page":"Init, Overrides, and Runtime Inputs","title":"Init and Override Specs","text":"","category":"section"},{"location":"user/inputs_overrides/","page":"Init, Overrides, and Runtime Inputs","title":"Init, Overrides, and Runtime Inputs","text":"Init and Override target one algorithm or state. Use the same reference style you used when adding that target to the composition: the type, the saved instance, a saved Unique(...) value, or an explicit symbol key.","category":"page"},{"location":"user/inputs_overrides/#API","page":"Init, Overrides, and Runtime Inputs","title":"API","text":"","category":"section"},{"location":"user/inputs_overrides/","page":"Init, Overrides, and Runtime Inputs","title":"Init, Overrides, and Runtime Inputs","text":"Init(target; name = value, ...)\nOverride(target; name = value, ...)","category":"page"},{"location":"user/inputs_overrides/","page":"Init, Overrides, and Runtime Inputs","title":"Init, Overrides, and Runtime Inputs","text":"Pair syntax is also accepted:","category":"page"},{"location":"user/inputs_overrides/","page":"Init, Overrides, and Runtime Inputs","title":"Init, Overrides, and Runtime Inputs","text":"Init(target, :name => value)\nOverride(target, :name => value)","category":"page"},{"location":"user/inputs_overrides/","page":"Init, Overrides, and Runtime Inputs","title":"Init, Overrides, and Runtime Inputs","text":"Targets are resolved through the composed algorithm registry: the table of registered algorithms and states for the final process. After resolving, the target namespace is stored in the spec type and the matched registry entry is kept as ref for display and inspection.","category":"page"},{"location":"user/inputs_overrides/#When-They-Apply","page":"Init, Overrides, and Runtime Inputs","title":"When They Apply","text":"","category":"section"},{"location":"user/inputs_overrides/","page":"Init, Overrides, and Runtime Inputs","title":"Init, Overrides, and Runtime Inputs","text":"init(la, specs...) applies persistent setup in this order:","category":"page"},{"location":"user/inputs_overrides/","page":"Init, Overrides, and Runtime Inputs","title":"Init, Overrides, and Runtime Inputs","text":"Init specs are merged into target subcontexts.\ninit(...) executes.\nOverride specs are merged after init.","category":"page"},{"location":"user/inputs_overrides/","page":"Init, Overrides, and Runtime Inputs","title":"Init, Overrides, and Runtime Inputs","text":"So:","category":"page"},{"location":"user/inputs_overrides/","page":"Init, Overrides, and Runtime Inputs","title":"Init, Overrides, and Runtime Inputs","text":"Init is for values needed during initialization.\nOverride force-replaces initialized values.","category":"page"},{"location":"user/inputs_overrides/#Stored-Lifecycle-Specs","page":"Init, Overrides, and Runtime Inputs","title":"Stored Lifecycle Specs","text":"","category":"section"},{"location":"user/inputs_overrides/","page":"Init, Overrides, and Runtime Inputs","title":"Init, Overrides, and Runtime Inputs","text":"Initialized loop algorithms store their Init and Override specs. Calling init(la) again replays the stored specs and rebuilds the full persistent context.","category":"page"},{"location":"user/inputs_overrides/","page":"Init, Overrides, and Runtime Inputs","title":"Init, Overrides, and Runtime Inputs","text":"Passed specs override stored specs per target:","category":"page"},{"location":"user/inputs_overrides/","page":"Init, Overrides, and Runtime Inputs","title":"Init, Overrides, and Runtime Inputs","text":"initialized = init(algo, Init(Walker; dt = 0.01))\nupdated = init(initialized, Init(Walker; dt = 0.02))","category":"page"},{"location":"user/inputs_overrides/","page":"Init, Overrides, and Runtime Inputs","title":"Init, Overrides, and Runtime Inputs","text":"partialinit(la, specs...) rebuilds only the targeted algorithms or states:","category":"page"},{"location":"user/inputs_overrides/","page":"Init, Overrides, and Runtime Inputs","title":"Init, Overrides, and Runtime Inputs","text":"la = partialinit(la, Init(Walker; dt = 0.02))","category":"page"},{"location":"user/inputs_overrides/","page":"Init, Overrides, and Runtime Inputs","title":"Init, Overrides, and Runtime Inputs","text":"Both init and partialinit return a loop algorithm. Callers should use the returned value because the concrete context type may change.","category":"page"},{"location":"user/inputs_overrides/#Example","page":"Init, Overrides, and Runtime Inputs","title":"Example","text":"","category":"section"},{"location":"user/inputs_overrides/","page":"Init, Overrides, and Runtime Inputs","title":"Init, Overrides, and Runtime Inputs","text":"algo = CompositeAlgorithm(Walker, InsertNoise, (1, 2))\n\np = Process(\n    algo,\n    Init(Walker; dt = 0.01),\n    Override(InsertNoise; seed = 1234),\n    repeats = 100,\n)","category":"page"},{"location":"user/inputs_overrides/","page":"Init, Overrides, and Runtime Inputs","title":"Init, Overrides, and Runtime Inputs","text":"Use repeats = 100 for a fixed number of process loop iterations, or lifetime = Repeat(100) if you want to pass the lifetime object explicitly.","category":"page"},{"location":"user/inputs_overrides/#Targeting-and-Identity","page":"Init, Overrides, and Runtime Inputs","title":"Targeting and Identity","text":"","category":"section"},{"location":"user/inputs_overrides/","page":"Init, Overrides, and Runtime Inputs","title":"Init, Overrides, and Runtime Inputs","text":"When choosing targets, use the same references you used in composition.","category":"page"},{"location":"user/inputs_overrides/","page":"Init, Overrides, and Runtime Inputs","title":"Init, Overrides, and Runtime Inputs","text":"For exact patterns and examples, see Referencing Algorithms.","category":"page"},{"location":"user/inputs_overrides/#Runtime-@input","page":"Init, Overrides, and Runtime Inputs","title":"Runtime @input","text":"","category":"section"},{"location":"user/inputs_overrides/","page":"Init, Overrides, and Runtime Inputs","title":"Init, Overrides, and Runtime Inputs","text":"Runtime inputs are declared on a @CompositeAlgorithm or @Routine with @input. They are passed as keyword arguments to run, validated before loop execution, and merged into the transient ProcessContext._input field for that run only.","category":"page"},{"location":"user/inputs_overrides/","page":"Init, Overrides, and Runtime Inputs","title":"Init, Overrides, and Runtime Inputs","text":"algo = @CompositeAlgorithm begin\n    @state energy = 0.0\n    @input temperature::AbstractFloat\n    @input sweep = 1\n\n    step = metropolis(energy, temperature; sweep = sweep)\nend\n\nla = init(resolve(algo))\nla = run(la; temperature = 2.0)","category":"page"},{"location":"user/inputs_overrides/","page":"Init, Overrides, and Runtime Inputs","title":"Init, Overrides, and Runtime Inputs","text":"Runtime inputs are not stored in the loop algorithm. After the run finishes, the stored persistent context excludes runtime _input values.","category":"page"},{"location":"user/inputs_overrides/","page":"Init, Overrides, and Runtime Inputs","title":"Init, Overrides, and Runtime Inputs","text":"Input declarations support:","category":"page"},{"location":"user/inputs_overrides/","page":"Init, Overrides, and Runtime Inputs","title":"Init, Overrides, and Runtime Inputs","text":"@input required_name\n@input typed_name::AbstractFloat\n@input defaulted_name = 1","category":"page"},{"location":"user/inputs_overrides/","page":"Init, Overrides, and Runtime Inputs","title":"Init, Overrides, and Runtime Inputs","text":"Rules:","category":"page"},{"location":"user/inputs_overrides/","page":"Init, Overrides, and Runtime Inputs","title":"Init, Overrides, and Runtime Inputs","text":"Required inputs must be passed to run.\nUnknown runtime keyword arguments are rejected.\nTyped inputs are checked with isa.\nDefaults are used when defaulted inputs are omitted.","category":"page"},{"location":"user/inputs_overrides/","page":"Init, Overrides, and Runtime Inputs","title":"Init, Overrides, and Runtime Inputs","text":"For a Process, pass the same runtime inputs to run:","category":"page"},{"location":"user/inputs_overrides/","page":"Init, Overrides, and Runtime Inputs","title":"Init, Overrides, and Runtime Inputs","text":"p = Process(algo; repeats = 100)\nrun(p; temperature = 2.0)","category":"page"},{"location":"user/init_analysis/#init_analysis_user","page":"Init Analysis","title":"Init Analysis","text":"","category":"section"},{"location":"user/init_analysis/","page":"Init Analysis","title":"Init Analysis","text":"ContextAnalyser is a lightweight, best-effort tool for discovering which values an entity's init and step! methods try to read.","category":"page"},{"location":"user/init_analysis/","page":"Init Analysis","title":"Init Analysis","text":"It is meant for exploratory analysis, not for exact validation. When an init path eventually errors because a missing value turned into nothing, analysis stops for that path and only the accesses up to that point are recorded.","category":"page"},{"location":"user/init_analysis/","page":"Init Analysis","title":"Init Analysis","text":"Use it when you are not sure which Input(...), Route(...), or Share(...) values an algorithm needs. The analyzer runs your hooks with a recording context instead of a normal runtime context.","category":"page"},{"location":"user/init_analysis/#Loading-It","page":"Init Analysis","title":"Loading It","text":"","category":"section"},{"location":"user/init_analysis/","page":"Init Analysis","title":"Init Analysis","text":"The analyzer lives in src/ContextAnalyzer/ContextAnalyzer.jl and is currently opt-in.","category":"page"},{"location":"user/init_analysis/","page":"Init Analysis","title":"Init Analysis","text":"Load it into the module with:","category":"page"},{"location":"user/init_analysis/","page":"Init Analysis","title":"Init Analysis","text":"using Processes\nBase.include(Processes, joinpath(dirname(pathof(Processes)), \"ContextAnalyzer\", \"ContextAnalyzer.jl\"))","category":"page"},{"location":"user/init_analysis/#Running-Analysis","page":"Init Analysis","title":"Running Analysis","text":"","category":"section"},{"location":"user/init_analysis/","page":"Init Analysis","title":"Init Analysis","text":"Use analyse_inits on a loop algorithm:","category":"page"},{"location":"user/init_analysis/","page":"Init Analysis","title":"Init Analysis","text":"analysis = Processes.analyse_inits(comp)","category":"page"},{"location":"user/init_analysis/","page":"Init Analysis","title":"Init Analysis","text":"This first builds a mock loop algorithm from the resolved one, with all repeats and intervals normalized to 1. It then creates analyzer views with view(...) and runs each flattened init inside a try block.","category":"page"},{"location":"user/init_analysis/","page":"Init Analysis","title":"Init Analysis","text":"The analyzer records:","category":"page"},{"location":"user/init_analysis/","page":"Init Analysis","title":"Init Analysis","text":"which registered context entries were opened,\nwhich names each entry requested through context.x, get(context, :x, default), haskey(context, :x), or indexing,\na compact count of captured errors,\nstored per-view inputs that were seeded or produced during successful init calls.","category":"page"},{"location":"user/init_analysis/#Analysing-Steps","page":"Init Analysis","title":"Analysing Steps","text":"","category":"section"},{"location":"user/init_analysis/","page":"Init Analysis","title":"Init Analysis","text":"Use analyse_steps when you want to probe runtime reads as well:","category":"page"},{"location":"user/init_analysis/","page":"Init Analysis","title":"Init Analysis","text":"analysis = Processes.analyse_steps(comp)","category":"page"},{"location":"user/init_analysis/","page":"Init Analysis","title":"Init Analysis","text":"By default this first runs the init analysis pass and then executes each flattened step-capable leaf once from that mock loop algorithm.","category":"page"},{"location":"user/init_analysis/","page":"Init Analysis","title":"Init Analysis","text":"You can disable the init pass when you already have enough seeded state:","category":"page"},{"location":"user/init_analysis/","page":"Init Analysis","title":"Init Analysis","text":"analysis = Processes.analyse_steps(comp; init = false, inputs = (; ...))","category":"page"},{"location":"user/init_analysis/","page":"Init Analysis","title":"Init Analysis","text":"Step analysis is still best-effort. It is most useful for discovering direct reads from the view. It does not try to perfectly reproduce every runtime routing/share writeback case.","category":"page"},{"location":"user/init_analysis/#Seeding-Inputs","page":"Init Analysis","title":"Seeding Inputs","text":"","category":"section"},{"location":"user/init_analysis/","page":"Init Analysis","title":"Init Analysis","text":"You can pass per-view inputs with the inputs keyword:","category":"page"},{"location":"user/init_analysis/","page":"Init Analysis","title":"Init Analysis","text":"analysis = Processes.analyse_inits(\n    comp;\n    inputs = (;\n        CaptureSeed_1 = (; seed = 4, scale = 2.0),\n        DirectContextRead_1 = (; noise = 8.0),\n    ),\n)","category":"page"},{"location":"user/init_analysis/","page":"Init Analysis","title":"Init Analysis","text":"These inputs are keyed by the registered context names, such as :CaptureSeed_1.","category":"page"},{"location":"user/init_analysis/","page":"Init Analysis","title":"Init Analysis","text":"Within a view:","category":"page"},{"location":"user/init_analysis/","page":"Init Analysis","title":"Init Analysis","text":"haskey(context, :x) returns true when x was seeded for that view,\nget(context, :x, default) returns the seeded value,\ncontext.x returns the seeded value,\nsuccessful init and step! return values are merged back into the analyzer's stored inputs.","category":"page"},{"location":"user/init_analysis/","page":"Init Analysis","title":"Init Analysis","text":"That makes iterative analysis possible: seed what you already know, run analysis, inspect what is still requested, then rerun with more inputs in place.","category":"page"},{"location":"user/init_analysis/#Reading-Results","page":"Init Analysis","title":"Reading Results","text":"","category":"section"},{"location":"user/init_analysis/","page":"Init Analysis","title":"Init Analysis","text":"The default display is intentionally compact:","category":"page"},{"location":"user/init_analysis/","page":"Init Analysis","title":"Init Analysis","text":"println(analysis)","category":"page"},{"location":"user/init_analysis/","page":"Init Analysis","title":"Init Analysis","text":"Use these helpers for programmatic access:","category":"page"},{"location":"user/init_analysis/","page":"Init Analysis","title":"Init Analysis","text":"Processes.requested_inputs(analysis)\nProcesses.stored_inputs(analysis)\nanalysis.memory.errors","category":"page"},{"location":"user/init_analysis/","page":"Init Analysis","title":"Init Analysis","text":"requested_inputs(analysis) returns a dictionary of:","category":"page"},{"location":"user/init_analysis/","page":"Init Analysis","title":"Init Analysis","text":"view_key => Vector{Symbol}","category":"page"},{"location":"user/init_analysis/","page":"Init Analysis","title":"Init Analysis","text":"showing which symbols that view requested during analysis.","category":"page"},{"location":"user/init_analysis/#Printing-Events","page":"Init Analysis","title":"Printing Events","text":"","category":"section"},{"location":"user/init_analysis/","page":"Init Analysis","title":"Init Analysis","text":"Event traces are not printed by default. Print them explicitly with:","category":"page"},{"location":"user/init_analysis/","page":"Init Analysis","title":"Init Analysis","text":"Processes.printevents(analysis)","category":"page"},{"location":"user/init_analysis/","page":"Init Analysis","title":"Init Analysis","text":"This prints the recorded view, getproperty, get, haskey, and getindex events in order.","category":"page"},{"location":"user/init_analysis/#Forms-That-Analyse-Well","page":"Init Analysis","title":"Forms That Analyse Well","text":"","category":"section"},{"location":"user/init_analysis/","page":"Init Analysis","title":"Init Analysis","text":"The analyzer only sees what goes through the context/view surface. These forms work best:","category":"page"},{"location":"user/init_analysis/","page":"Init Analysis","title":"Init Analysis","text":"required reads through context.x or destructuring like (; x, y) = context\noptional reads through get(context, :x, default)\nexplicit presence checks through haskey(context, :x)\nexplicit indexed reads like context[:OtherAlgo_1] or context[algo_ref]\n@ProcessAlgorithm ... @inputs((; ...)) for init-only requirements\nstep! methods that return plain NamedTuples with stable output names","category":"page"},{"location":"user/init_analysis/","page":"Init Analysis","title":"Init Analysis","text":"These forms are harder to analyse accurately:","category":"page"},{"location":"user/init_analysis/","page":"Init Analysis","title":"Init Analysis","text":"dynamically constructed property names or keys\nreads from globals, closures, captured mutable state, files, or random external sources\ncontrol flow where a missing value quickly becomes nothing and errors before later accesses happen\nstep paths that depend on exact routed writeback behavior across subcontexts","category":"page"},{"location":"user/init_analysis/","page":"Init Analysis","title":"Init Analysis","text":"If you want better analysis results, prefer direct view reads over indirect lookup logic.","category":"page"},{"location":"user/init_analysis/#Typical-Workflow","page":"Init Analysis","title":"Typical Workflow","text":"","category":"section"},{"location":"user/init_analysis/","page":"Init Analysis","title":"Init Analysis","text":"Run analyse_inits(comp) once.\nInspect Processes.requested_inputs(analysis).\nSeed the next round with analyse_inits(comp; inputs = ...).\nRepeat until the interesting init paths stop asking for unknown values.","category":"page"},{"location":"user/running/#running_user","page":"Running, Wait, Fetch","title":"Running, Wait, Fetch","text":"","category":"section"},{"location":"user/running/","page":"Running, Wait, Fetch","title":"Running, Wait, Fetch","text":"This page covers the normal runtime flow: create a Process, run it, wait for it, and inspect the result.","category":"page"},{"location":"user/running/#Create-a-Process","page":"Running, Wait, Fetch","title":"Create a Process","text":"","category":"section"},{"location":"user/running/","page":"Running, Wait, Fetch","title":"Running, Wait, Fetch","text":"p = Process(algo, Init(...), Override(...); repeats = 1_000)","category":"page"},{"location":"user/running/","page":"Running, Wait, Fetch","title":"Running, Wait, Fetch","text":"Process(...) resolves the loop algorithm when needed, runs the lifecycle init path, and stores the algorithm plus its current context on the process.","category":"page"},{"location":"user/running/","page":"Running, Wait, Fetch","title":"Running, Wait, Fetch","text":"Persistent context is built from Init(...), Override(...), @state, routes, shares, and managed state. Runtime @input values are not stored at construction time.","category":"page"},{"location":"user/running/#Run-and-Resume","page":"Running, Wait, Fetch","title":"Run and Resume","text":"","category":"section"},{"location":"user/running/","page":"Running, Wait, Fetch","title":"Running, Wait, Fetch","text":"run(p)","category":"page"},{"location":"user/running/","page":"Running, Wait, Fetch","title":"Running, Wait, Fetch","text":"run(p) starts the process loop task. If the process was paused, run(p) resumes the suspended runtime context; new runtime inputs, init specs, and lifetime changes are rejected during resume.","category":"page"},{"location":"user/running/","page":"Running, Wait, Fetch","title":"Running, Wait, Fetch","text":"If the loop algorithm declares runtime @input values, pass them as run keywords:","category":"page"},{"location":"user/running/","page":"Running, Wait, Fetch","title":"Running, Wait, Fetch","text":"run(p; temperature = 2.0, sweep = 10)","category":"page"},{"location":"user/running/","page":"Running, Wait, Fetch","title":"Running, Wait, Fetch","text":"The keywords are converted to a NamedTuple, validated against the algorithm's runtime input declarations, and merged into ProcessContext._input only for that loop run. Finished processes strip runtime-only fields before storing their persistent context. A paused process may keep its live runtime context internally so it can resume.","category":"page"},{"location":"user/running/","page":"Running, Wait, Fetch","title":"Running, Wait, Fetch","text":"Initialized loop algorithms can also be run directly:","category":"page"},{"location":"user/running/","page":"Running, Wait, Fetch","title":"Running, Wait, Fetch","text":"la = init(resolve(algo), Init(MyAlgo; buffer = Float64[]))\nla = run(la; temperature = 2.0)","category":"page"},{"location":"user/running/","page":"Running, Wait, Fetch","title":"Running, Wait, Fetch","text":"The returned loop algorithm contains the next persistent context. Use the returned value; runtime inputs are stripped before the context is stored back on the returned algorithm.","category":"page"},{"location":"user/running/#Lifetime","page":"Running, Wait, Fetch","title":"Lifetime","text":"","category":"section"},{"location":"user/running/","page":"Running, Wait, Fetch","title":"Running, Wait, Fetch","text":"Stop behavior can be given either as a simple repeat count or as a lifetime object:","category":"page"},{"location":"user/running/","page":"Running, Wait, Fetch","title":"Running, Wait, Fetch","text":"repeats = 1000 -> run a fixed number of iterations.\nomitted -> default lifetime behavior for that algorithm type.\nadvanced: lifetime = Repeat(...), lifetime = Indefinite(), lifetime = Until(...), lifetime = RepeatOrUntil(...).","category":"page"},{"location":"user/running/","page":"Running, Wait, Fetch","title":"Running, Wait, Fetch","text":"See Lifetime for full details. For selector syntax used in Until, see Vars (Var Selectors).","category":"page"},{"location":"user/running/#Control-Operations","page":"Running, Wait, Fetch","title":"Control Operations","text":"","category":"section"},{"location":"user/running/","page":"Running, Wait, Fetch","title":"Running, Wait, Fetch","text":"pause(p): stop loop while keeping resumable state.\nrun(p): start a new task or resume after pause.\nclose(p): stop the process and collect the final task result into the stored process context.\nreinit(p): compatibility helper that pauses, reruns lifecycle init, and runs again.\npartialinit(la, specs...): rebuild only the targeted algorithms or states on an initialized loop algorithm.","category":"page"},{"location":"user/running/#Waiting-and-Fetching","page":"Running, Wait, Fetch","title":"Waiting and Fetching","text":"","category":"section"},{"location":"user/running/","page":"Running, Wait, Fetch","title":"Running, Wait, Fetch","text":"wait(p): block until task completes.\nfetch(p): return the task return value.","category":"page"},{"location":"user/running/","page":"Running, Wait, Fetch","title":"Running, Wait, Fetch","text":"In practice:","category":"page"},{"location":"user/running/","page":"Running, Wait, Fetch","title":"Running, Wait, Fetch","text":"use wait(p) when you just want to block until completion,\nuse fetch(p) when you want the task's return value,\nuse context(p) for the stored persistent process context,\nuse getcontext(p) when you want that context with the process injected into globals.","category":"page"},{"location":"user/running/#Status-Helpers","page":"Running, Wait, Fetch","title":"Status Helpers","text":"","category":"section"},{"location":"user/running/","page":"Running, Wait, Fetch","title":"Running, Wait, Fetch","text":"isrunning(p)\nispaused(p)\nisdone(p)\nisidle(p)","category":"page"},{"location":"user/running/#Inline-Process","page":"Running, Wait, Fetch","title":"Inline Process","text":"","category":"section"},{"location":"user/running/","page":"Running, Wait, Fetch","title":"Running, Wait, Fetch","text":"Use InlineProcess when you want synchronous execution without a separate process task. It accepts the same positional Init(...)/Input(...) and Override(...) arguments as Process(...):","category":"page"},{"location":"user/running/","page":"Running, Wait, Fetch","title":"Running, Wait, Fetch","text":"ip = InlineProcess(algo, Init(...), Override(...); repeats = 10_000)\nrun(ip)","category":"page"},{"location":"user/running/","page":"Running, Wait, Fetch","title":"Running, Wait, Fetch","text":"InlineProcess also accepts lifetime = 10_000 and converts it to a repeat count. For Process, use repeats = 10_000 or lifetime = Repeat(10_000). Unlike Process, InlineProcess stores a context that can be absorbed back into an algorithm, so runtime-only fields such as :_input and process are stripped after the loop. Like finished Process runs, this means the stored context is the persistent context shape rather than the transient loop context.","category":"page"},{"location":"user/running/","page":"Running, Wait, Fetch","title":"Running, Wait, Fetch","text":"If you need buffered external updates to context variables, see Interactive Contexts.","category":"page"},{"location":"compile_optimization_notes/#Compile-Optimization-Notes","page":"Compile Optimization Notes","title":"Compile Optimization Notes","text":"","category":"section"},{"location":"compile_optimization_notes/","page":"Compile Optimization Notes","title":"Compile Optimization Notes","text":"Potential next targets, in the order they should be investigated:","category":"page"},{"location":"compile_optimization_notes/","page":"Compile Optimization Notes","title":"Compile Optimization Notes","text":"Reduce the remaining generated merge/context code. The latest profile still shows merge_into_subcontext_*, merge_into_subcontexts, generated ProcessContext construction, and generated SubContextView getproperty in the first-run compile path. The single-name lookup already removed the biggest get_all_locations cost; the next step should be smaller emitted expressions, not more background tasks.\nCheck whether get_all_locations is still needed in normal non-error paths. It should now be mostly property enumeration, explicit keys/propertynames, and error reporting. If profiles show it from normal execution again, trace the exact caller before adding a cache.\nCheck first-step and steady-step duplication. Repeat loops compile an unstable first step and a stable steady loop. For algorithms whose context type cannot grow, there may be a way to skip or shrink the unstable generated path.\nIsolate context init merge cost. Lifecycle init now resolves Init/Override specs and stores them on the initialized loop algorithm. The remaining cost is probably applying named specs through generated context merge/init code. Benchmark init(la) with and without specs separately.\nCache resolved algorithm metadata by concrete loop algorithm type. Registry setup, flat funcs/states/multipliers, and share/route resolution are mostly type-structural. This must account for mutable algorithm instances and options that are value-dependent.\nSplit generated step compilation only where the semantic boundary is clear. Avoid random helper churn. Candidate boundaries are route lookup, context view access, and merge planning. The goal is to let shared structural parts compile once while keeping the final concrete setter fast.\nBenchmark copyprocess and context copy cost separately. Learning workloads copy template contexts often. Measure whether deepcopy(context) or fresh structural init is more expensive for realistic contexts.\nKeep Process first-entry context concrete but resumed context broad. The stored LoopAlgorithm context is already concrete and should remain the first-run source. Process.runtime_context is deliberately Union{Nothing, ProcessContext} for resumed/replaced contexts; do not add a Process{F,C} parameter again unless a new profile shows a real win.\nKeep empty tuple paths specialized. Empty inputs, overrides, options, shares, and routes are common and should avoid generic filtering/merging.\nKeep the compile benchmark suite current.  Report package load separately from stage timings, and keep cold and warm  stage measurements separate.\nRevisit background precompile only from values close to first use.  Process-constructor loop precompile has been useful enough to keep.  LoopAlgorithm-constructor metadata precompile was too early and contended  with construction/input resolution. Any new background precompile should be  measured against total construct-to-first-run time, not construction alone.\nAvoid precompile hooks that only move work earlier.  Constructor loop precompile should target exact first-run signatures.  Resolve-time precompile and broad metadata precompile have both been tested  and made immediate TTFP worse. The next useful precompile work is probably  reducing the amount of generated user-algorithm-specific code, not launching  more tasks earlier.","category":"page"},{"location":"compile_optimization_attempts/#Compile-Optimization-Attempts","page":"Compile Optimization Attempts","title":"Compile Optimization Attempts","text":"","category":"section"},{"location":"compile_optimization_attempts/","page":"Compile Optimization Attempts","title":"Compile Optimization Attempts","text":"This file records compile-latency experiments so failed paths are not repeated.","category":"page"},{"location":"compile_optimization_attempts/","page":"Compile Optimization Attempts","title":"Compile Optimization Attempts","text":"Some older entries below mention TaskData. That type has been removed from the active lifecycle; those notes are retained as historical compile-latency context only.","category":"page"},{"location":"compile_optimization_attempts/#Kept-Changes","page":"Compile Optimization Attempts","title":"Kept Changes","text":"","category":"section"},{"location":"compile_optimization_attempts/","page":"Compile Optimization Attempts","title":"Compile Optimization Attempts","text":"Captured concrete loop algorithm types in helper signatures. This replaced several Type{<:T} method arguments with Type{Concrete} where Concrete <: T when the method reads the exact type.\nAdded constructor-time ProcessManager precompile scheduling. The hook runs after manager construction and targets concrete manager, slot, and job types.\nKept constructor-time Process loop precompile scheduling. This is close enough to the first run call to reduce first-run latency without precompiling broad LoopAlgorithm metadata paths too early. The precompile signature now targets the actual non-generated loop method: loop(process, algo, context, lifetime, inputs, Resuming{false}, NonGenerated). The previous signature omitted inputs and Resuming, so it aimed at a wrapper shape that did not match the first-run call.\nMoved process loop precompile helpers to ProcessPrecompile.jl and removed lock/dedup task bookkeeping. The construction hook now schedules a plain best-effort precompile task, and first run no longer waits on or coordinates a global precompile task registry. This reduced nearby constructor overhead and made the profile easier to read.\nAdded a narrow SimpleAlgo(single_algorithm) construction fast path. The common one-algorithm case now builds the simple LoopAlgorithm directly instead of going through the full CompositeAlgorithm parser and flatten_comp_funcs. intervals(::SimpleAlgo) still returns Interval(1) values so existing multiplier code sees the same shape.\nReduced generation-time work in context constructors and merges. Generated helpers now use simple static loops instead of closure-based all/filter/findfirst scans, and _merge_into_globals constructs a ProcessContext directly instead of going through the generic setfield generated helper.\nAdded single-name SubContextView location lookup for generated read and merge paths. Normal getproperty(view, Val(name)), haskey(view, Val(name)), and stablemerge/unstablemerge planning no longer build the full location table just to resolve one name. The full get_all_locations path remains for property enumeration and error reporting.\nAvoided empty process setup work. Empty input/override construction now skips a throwaway context build, and empty initcontext paths avoid vararg filtering.\nMoved setfield debug rendering out of generated-function generation. Large debug strings are now built only on the error path.\nMade input/override resolution require a resolved algorithm. prepare_process_constructor resolves the normalized algorithm before resolving inputs or overrides. resolve_process_inputs_overrides now reads the registry from that resolved algorithm and errors when called directly with an unresolved algorithm. This is mostly a contract cleanup; measured compile latency was neutral against the same benchmark using an already-resolved algorithm.\nFused single-algorithm resolve registry build with algorithm keying. The single-argument path now uses the keyed algorithm returned while adding algorithms to the registry instead of building a registry and then doing a second registry lookup pass through update_keys. Multi-algorithm resolve still uses the shared-registry path.\nBound concrete value argument types in the resolve/materialization helpers. Changing signatures such as la::LoopAlgorithm and registry::NameSpaceRegistry to la::LA where LA<:LoopAlgorithm and registry::R where R<:NameSpaceRegistry improved the full process benchmark after the fused resolve change. This is not only useful for Type arguments; it can help value arguments too.\nAdded narrow lifecycle/input resolution fast paths. init(la, Input(...), Override(...)) now resolves specs through typed methods for empty, already-named, and raw Init/Override tuples. Context construction receives the already-resolved lifecycle-stripped algorithm, so it does not resolve again. The public input/override resolver also has a typed all-Input/Override path while preserving the old generic fallback.\nInlined only small setup-path accessors and wrappers that improved the simple compile benchmark. The retained inline hints are on the resolve preparation chain, lifecycle constructor helpers, input/override accessors, and generic LoopAlgorithm interface accessors.\nKept the normal first-entry Process context on the concrete algorithm path. Process.runtime_context now starts as nothing; makeloop! reads the stored algorithm context for the first run and only falls back to runtime_context after external context replacement or a returned runtime context. This removes the runtime_context::Any leak from the first-entry loop path without changing the public context(process) behavior after a run. The runtime field itself is now Union{Nothing, ProcessContext} rather than Any, so resumed contexts are intentionally abstract only at the ProcessContext level.\nKept concrete stored contexts on initialized LoopAlgorithm values. CompositeAlgorithm and Routine both store context::C, where C is a type parameter. For an initialized algorithm, fieldtype(typeof(la), :context) === typeof(getstoredcontext(la)) holds, and the first-entry process path through _typed_runtime_context(process) infers the exact ProcessContext{...} type.\nExtended the PrecompileTools workload for the managed @ProcessAlgorithm normal Process path. The workload now covers SimpleAlgo(_ProcessPrecompileManaged), typed Input/Override resolution, lifecycle init(...; lifetime = Repeat(1)), Process(...), first run, and construction from an already initialized algorithm. This covers the package-side version of the compile benchmark's managed lifecycle path. It cannot remove compilation of user-defined Main.@ProcessAlgorithm generated methods, but it does precompile the package helper methods those generated algorithms call.\nAdded narrow @nospecialize barriers on Base.wait(::Process) and Base.fetch(::Process). These methods only touch p.task or p.lastresult, so they do not need a separate specialization for every full Process{CompositeAlgorithm{...}} type. A trace-compile pass on the simple TTFP script dropped from about 137 lines to about 116 lines after the exact loop precompile and wait/fetch barriers.","category":"page"},{"location":"compile_optimization_attempts/#Reverted-Or-Rejected","page":"Compile Optimization Attempts","title":"Reverted Or Rejected","text":"","category":"section"},{"location":"compile_optimization_attempts/","page":"Compile Optimization Attempts","title":"Compile Optimization Attempts","text":"@nospecialize on process precompile helpers. Julia accepts both formal-argument and statement-position @nospecialize, but the tested changes made latency noisier or worse.\nGenerated location caching for subcontext views. The idea was to cache location computation in generated helpers. In the tested pattern it did not improve the target benchmark.\nRefactoring stablemerge/unstablemerge merge planning. Several versions using grouped plans and helper functions were neutral or slower.\nStructural helpers for _global_context_type and related loop precompile signatures. They passed tests but worsened construction/first-run latency.\nReusing the input-resolution ProcessContext through a public TaskData keyword option. This avoided one duplicate context build, but introduced a new constructor specialization path and did not produce a stable win.\nReusing the input-resolution ProcessContext through a narrow internal Process constructor path. This avoided one duplicate context build for Process(algo, Input(...), Override(...)), but did not improve the compile-latency benchmark. The first call is dominated by compilation of resolution, merge, init, and run paths; after compilation, warm process construction is already small enough that the saved context build is below benchmark noise. This was removed to keep the constructor path simpler.\nSplitting TaskData into a typed positional internal helper. This was meant to avoid keyword dispatch in Process construction. It increased cold-stage latency in the compile benchmark.\nAdding type parameters directly to the public TaskData keyword constructor. This also worsened compile-facing benchmark numbers and was reverted.\nConstructor-time LoopAlgorithm metadata precompile. Immediate scheduling made nearby construction and input-resolution stages contend with background compilation. Adding an arbitrary sleep moved the contention but did not reliably improve immediate time-to-first-process-run. The hook, lock, type set, delay constant, and metadata precompile helper were removed.\nSplitting setup_registry into an add_loopalgorithm_to_registry helper. Both a fully specialized helper and a variant with @nospecialize on the loop algorithm were tested. The split made cold construction/first-run latency worse and also hurt warmed process-loop timing, so the original single-body registry setup remains preferable.\nAdding a @noinline unresolved-resolve boundary. The goal was to stop Process construction from compiling through the full resolve path. In practice it made first-run and warmed process-loop timing worse, which suggests the resolved algorithm type information is still useful to the later loop path.\nAdding Base.@constprop :none to setup_registry. This was meant to reduce caller-side compile work without changing semantics, but it worsened warmed loop timing and was removed.\nRewriting only resolve(la::LoopAlgorithm) as resolve(la::LA) where {LA<:LoopAlgorithm} before the fused resolve change. Isolated to the old resolve implementation, this did not improve the compile benchmark. After the fused single-resolve implementation, applying the pattern consistently to the resolve helper chain did improve the full process benchmark.\nBroad @inline pass over Process utility helpers. Inlining one-hop helpers around process state, runtime, precompile signatures, and loop scheduling did not improve direct time to first process run and made staged lifecycle/hot timings noisier, so it was reverted.\nBroad @inline pass over CompositeAlgorithm and Routine accessors. This worsened direct time to first process run substantially in the simple benchmark, with samples around 679 / 721 / 826 ms, so it was reverted. The useful inline hints are much narrower.\nAdding the process context type as a second Process{F,C} parameter. This made first-entry context access infer, but it also made the process type larger and worsened direct time to first run. The retained version keeps Process{F} and reads the typed context from getstoredcontext(getalgo(p)) while runtime_context is empty.\nType-level replacement for _global_context_type. A generated helper computed the context type for _merge_into_globals(context, (; process = p)) without doing the merge. It made staged Process construction slower, so the value-based implementation was restored.\nStripping :_input and :process before storing a finished Process context. This kept the typed first-entry path available after completion, but it changed the public context(process) result. Existing runtime-input tests expect those transient entries to remain visible after run/wait, so the stripping was reverted for Process.\nForcing context(process) to always return the stored loop algorithm context. This was tested as a temporary diagnostic to check whether the abstract runtime_context branch explained TTFP. It did not. With 8 Julia threads, direct time to first process run stayed at about 546-549 ms, matching the restored getter. The patch was reverted.\nAsync resolve(typeof(la)) precompile immediately after loop algorithm construction. A narrow manual test still worsened direct TTFP: with an explicit wait it was about 560-569 ms, and without waiting it was about 566-569 ms, compared with a current baseline around 547-552 ms. This confirms that resolve-time precompile is still too early for the immediate construct-and-run path.\nDisabling constructor loop precompile. This was neutral to slightly worse for direct TTFP and moved work from Process construction into first run. The constructor precompile remains useful, but only when it targets the exact loop signature.\n@nospecialize on run!(::Process). This wrapper looked like an easy compile barrier, but it regressed direct TTFP to about 571-578 ms, so it was reverted. run! should keep the concrete process type so the call into run/makeloop! remains well inferred.","category":"page"},{"location":"compile_optimization_attempts/#Current-Benchmark-Notes","page":"Compile Optimization Attempts","title":"Current Benchmark Notes","text":"","category":"section"},{"location":"compile_optimization_attempts/","page":"Compile Optimization Attempts","title":"Compile Optimization Attempts","text":"After the latest profiling pass on the simple managed @ProcessAlgorithm microbench with 8 Julia threads, direct construct-to-first-run timings were about 295 / 303 / 298 ms. Before these local changes the same path was around 516-529 ms; after only the SimpleAlgo fast path it was around 434-444 ms.\nThe main wins came from avoiding the full parser for single SimpleAlgo, not building full location tables for one-name view access/merge planning, and removing generic setfield from _merge_into_globals.\nmanual tests/ProcessHotLoopBenchmark.jl checks normal hot-loop runtime. Recent larger runs did not show a normal Process hot-loop regression against clean HEAD.\nmanual tests/ProcessCompileLatencyBenchmark.jl should break compile-facing work into algorithm construction, resolve, lifecycle init, Process constructor, first run, and warmed hot runs.\nmanual tests/ProcessResolveBenchmark.jl measures fresh construction, resolve, already-resolved resolve, initcontext, Process construction, first run, and warmed fresh-resolve throughput for simple, routed, shared, and nested algorithms.\nThe current benchmark should be refreshed against the lifecycle-init path. Metadata reuse should stay on narrow internal paths.\nCurrent lifecycle fast-path benchmark on 8 Julia threads: direct time to first process run is about 545-552 ms across cold Julia processes after the lifecycle/input refactor and first-entry context cleanup. Temporarily bypassing runtime_context entirely did not improve this number. The staged compile benchmark still shows the cold cost mainly in algorithm construction, Process construction, and first run; warmed construction and warmed first run are small.","category":"page"},{"location":"compile_optimization_attempts/#LoopAlgorithm-Stored-Context-Check","page":"Compile Optimization Attempts","title":"LoopAlgorithm Stored Context Check","text":"","category":"section"},{"location":"compile_optimization_attempts/","page":"Compile Optimization Attempts","title":"Compile Optimization Attempts","text":"The initialized loop algorithm context is typed correctly. A small diagnostic using a one-step CompositeAlgorithm showed:","category":"page"},{"location":"compile_optimization_attempts/","page":"Compile Optimization Attempts","title":"Compile Optimization Attempts","text":"typeof(la).parameters[6] is the concrete stored context type.\nfieldtype(typeof(la), :context) === typeof(getstoredcontext(la)).\ngetstoredcontext(la) infers the concrete ProcessContext{...}.\n_typed_runtime_context(process) infers the same concrete ProcessContext{...} before the process has stored a returned runtime context.","category":"page"},{"location":"compile_optimization_attempts/","page":"Compile Optimization Attempts","title":"Compile Optimization Attempts","text":"This means the remaining first-run compile cost is not caused by the stored LoopAlgorithm context being abstract. The intentionally abstract point is only the mutable Process.runtime_context after a runtime context has been stored or externally replaced.","category":"page"},{"location":"compile_optimization_attempts/#SnoopCompile-Pass","page":"Compile Optimization Attempts","title":"SnoopCompile Pass","text":"","category":"section"},{"location":"compile_optimization_attempts/","page":"Compile Optimization Attempts","title":"Compile Optimization Attempts","text":"Ran a temporary-environment SnoopCompile pass with SnoopCompileCore.@snoop_inference on the compile benchmark workload. The project dependency files were not changed.","category":"page"},{"location":"compile_optimization_attempts/","page":"Compile Optimization Attempts","title":"Compile Optimization Attempts","text":"Important exclusive inference-time signals from the small benchmark:","category":"page"},{"location":"compile_optimization_attempts/","page":"Compile Optimization Attempts","title":"Compile Optimization Attempts","text":"step! generated by @ProcessAlgorithm: about 55 ms.\nget_all_locations(::Type{<:SubContextView}): about 51 ms accumulated.\nBase.getproperty(::SubContextView, ::Val): about 44 ms accumulated.\n_merge_into_globals: about 35 ms accumulated.\nmerge_into_subcontext_rebuild: about 28 ms accumulated.\nmerge(::SubContextView, ::NamedTuple): about 25 ms.\ninit generated by @ProcessAlgorithm: about 25 ms.\nsetup_registry: about 19 ms.","category":"page"},{"location":"compile_optimization_attempts/","page":"Compile Optimization Attempts","title":"Compile Optimization Attempts","text":"Important inclusive paths:","category":"page"},{"location":"compile_optimization_attempts/","page":"Compile Optimization Attempts","title":"Compile Optimization Attempts","text":"resolve(::CompositeAlgorithm): about 207 ms, mostly through registry setup.\nloop(::Process, ::CompositeAlgorithm, ::ProcessContext, ::Repeat, ::NonGenerated): about 122 ms.\nlegacy initcontext(::TaskData{... inputs/overrides ...}): about 92 ms.\nProcess(...; repeats=1): about 87 ms.","category":"page"},{"location":"compile_optimization_attempts/","page":"Compile Optimization Attempts","title":"Compile Optimization Attempts","text":"The pass also showed inference under background precompile tasks launched from Process.jl. Future SnoopCompile runs should either disable those tasks or run a separate pass specifically for the precompile pipeline, otherwise normal workload inference and background precompile inference are mixed together.","category":"page"},{"location":"compile_optimization_attempts/#LoopAlgorithm-Metadata-Precompile","page":"Compile Optimization Attempts","title":"LoopAlgorithm Metadata Precompile","text":"","category":"section"},{"location":"compile_optimization_attempts/","page":"Compile Optimization Attempts","title":"Compile Optimization Attempts","text":"The first SnoopCompile pass showed background metadata precompile tasks mixed into normal first-call inference. The compile benchmark confirmed this was not just a measurement artifact: launching metadata precompile immediately from LoopAlgorithm construction made the next constructor stages contend with those tasks.","category":"page"},{"location":"compile_optimization_attempts/","page":"Compile Optimization Attempts","title":"Compile Optimization Attempts","text":"Measured cold-stage comparison on the simple compile benchmark:","category":"page"},{"location":"compile_optimization_attempts/","page":"Compile Optimization Attempts","title":"Compile Optimization Attempts","text":"Immediate background precompile: algo construction ~= 106 ms, input resolution ~= 118 ms, Process constructor ~= 63 ms, first run ~= 137 ms.\nDisabled metadata precompile: algo construction ~= 105 ms, input resolution ~= 30 ms, Process constructor ~= 61 ms, first run ~= 151 ms.\nDelayed metadata precompile by 0.2s: algo construction ~= 106 ms, input resolution ~= 27 ms, Process constructor ~= 54 ms, first run ~= 141 ms.","category":"page"},{"location":"compile_optimization_attempts/","page":"Compile Optimization Attempts","title":"Compile Optimization Attempts","text":"Later measurements showed the best immediate construct-to-first-run path came from removing the LoopAlgorithm constructor metadata precompile entirely while keeping the Process constructor loop precompile:","category":"page"},{"location":"compile_optimization_attempts/","page":"Compile Optimization Attempts","title":"Compile Optimization Attempts","text":"No LoopAlgorithm metadata precompile: algo construction ~= 87-90 ms, input resolution ~= 26-33 ms, Process constructor ~= 53-55 ms, first run ~= 123-134 ms.","category":"page"},{"location":"compile_optimization_attempts/","page":"Compile Optimization Attempts","title":"Compile Optimization Attempts","text":"The conclusion is that metadata precompile from LoopAlgorithm construction is too early for this workload. It either contends with input resolution or, when delayed, is less useful for the immediate first run. The retained precompile path is the Process constructor loop precompile, which is closer to the actual code that will run.","category":"page"},{"location":"user/value_semantics/#value_semantics_user","page":"Value Semantics and Unique","title":"Value Semantics and Unique","text":"","category":"section"},{"location":"user/value_semantics/","page":"Value Semantics and Unique","title":"Value Semantics and Unique","text":"Most users only need one rule here:","category":"page"},{"location":"user/value_semantics/","page":"Value Semantics and Unique","title":"Value Semantics and Unique","text":"if you use the same algorithm type once, plain types or instances are fine;\nif you need multiple logically distinct instances of the same algorithm, use Unique(...) and keep the returned value around.","category":"page"},{"location":"user/value_semantics/","page":"Value Semantics and Unique","title":"Value Semantics and Unique","text":"Unique exists to give one inserted algorithm a guaranteed separate identity in the registry and therefore a separate subcontext in the process context.","category":"page"},{"location":"user/value_semantics/#When-You-Need-Unique","page":"Value Semantics and Unique","title":"When You Need Unique","text":"","category":"section"},{"location":"user/value_semantics/","page":"Value Semantics and Unique","title":"Value Semantics and Unique","text":"You usually need Unique(...) when you want more than one copy of the same algorithm in a composition and you need to target them separately in:","category":"page"},{"location":"user/value_semantics/","page":"Value Semantics and Unique","title":"Value Semantics and Unique","text":"Route(...)\nShare(...)\nInput(...)\nOverride(...)\nVar(...)","category":"page"},{"location":"user/value_semantics/","page":"Value Semantics and Unique","title":"Value Semantics and Unique","text":"Example:","category":"page"},{"location":"user/value_semantics/","page":"Value Semantics and Unique","title":"Value Semantics and Unique","text":"producer_a = Producer()\nproducer_b = Unique(Producer())\nconsumer = Consumer()\n\nalgo = CompositeAlgorithm(\n    producer_a, producer_b, consumer,\n    (1, 1, 1),\n    Route(producer_b => consumer, :value),\n)","category":"page"},{"location":"user/value_semantics/","page":"Value Semantics and Unique","title":"Value Semantics and Unique","text":"Without Unique, repeated equal immutable values or repeated type-based entries can be treated as the same logical identity.","category":"page"},{"location":"user/value_semantics/#Matching-Rules","page":"Value Semantics and Unique","title":"Matching Rules","text":"","category":"section"},{"location":"user/value_semantics/","page":"Value Semantics and Unique","title":"Value Semantics and Unique","text":"For process entities (ProcessAlgorithm/ProcessState), the current matching rules are:","category":"page"},{"location":"user/value_semantics/","page":"Value Semantics and Unique","title":"Value Semantics and Unique","text":"an immutable instance that Julia can store directly in a type parameter matches by value,\na mutable or otherwise non-direct instance matches by object identity,\na type matches by that type.","category":"page"},{"location":"user/value_semantics/","page":"Value Semantics and Unique","title":"Value Semantics and Unique","text":"So Fib() and Fib are different identities.","category":"page"},{"location":"user/value_semantics/#Why-Instance-Lookup-Can-Be-Surprising","page":"Value Semantics and Unique","title":"Why Instance Lookup Can Be Surprising","text":"","category":"section"},{"location":"user/value_semantics/","page":"Value Semantics and Unique","title":"Value Semantics and Unique","text":"The practical rule is: reuse the same reference you inserted.","category":"page"},{"location":"user/value_semantics/","page":"Value Semantics and Unique","title":"Value Semantics and Unique","text":"Fresh values can be surprising:","category":"page"},{"location":"user/value_semantics/","page":"Value Semantics and Unique","title":"Value Semantics and Unique","text":"a fresh immutable value can match an equal inserted immutable value,\na fresh mutable value is a different object and normally does not match the inserted one,\na type such as Fib targets the type-based entry, not an instance entry like Fib().","category":"page"},{"location":"user/value_semantics/#Unique","page":"Value Semantics and Unique","title":"Unique","text":"","category":"section"},{"location":"user/value_semantics/","page":"Value Semantics and Unique","title":"Value Semantics and Unique","text":"Unique(x) wraps x in IdentifiableAlgo with a UUID identity.","category":"page"},{"location":"user/value_semantics/","page":"Value Semantics and Unique","title":"Value Semantics and Unique","text":"That gives a guaranteed separate registry identity and thus separate subcontext key, even when:","category":"page"},{"location":"user/value_semantics/","page":"Value Semantics and Unique","title":"Value Semantics and Unique","text":"two wrapped values are otherwise equal,\nthey were added by the same type,\nor they are hard to distinguish by normal Julia equality.","category":"page"},{"location":"user/value_semantics/#Recommended-Patterns","page":"Value Semantics and Unique","title":"Recommended Patterns","text":"","category":"section"},{"location":"user/value_semantics/","page":"Value Semantics and Unique","title":"Value Semantics and Unique","text":"One logical instance per type: plain type or instance is fine.\nMultiple logical instances of same algorithm: use Unique(...) and keep references.\nInputs/routes/shares for those distinct instances: reference the same Unique values you inserted into composition.","category":"page"},{"location":"user/referencing_algorithms/#referencing_algorithms_user","page":"Referencing Algorithms","title":"Referencing Algorithms","text":"","category":"section"},{"location":"user/referencing_algorithms/","page":"Referencing Algorithms","title":"Referencing Algorithms","text":"Use this page whenever you need to point to a specific algorithm in:","category":"page"},{"location":"user/referencing_algorithms/","page":"Referencing Algorithms","title":"Referencing Algorithms","text":"Route(...)\nShare(...)\nInput(...)\nOverride(...)","category":"page"},{"location":"user/referencing_algorithms/#One-Rule","page":"Referencing Algorithms","title":"One Rule","text":"","category":"section"},{"location":"user/referencing_algorithms/","page":"Referencing Algorithms","title":"Referencing Algorithms","text":"Reference algorithms the same way you inserted them into the composition.","category":"page"},{"location":"user/referencing_algorithms/","page":"Referencing Algorithms","title":"Referencing Algorithms","text":"Added by type -> reference by that type.\nAdded by saved instance variable -> reference by that same variable.\nAdded by Unique(...) -> reference by that same saved unique variable.","category":"page"},{"location":"user/referencing_algorithms/#Pattern-1:-Added-by-Type","page":"Referencing Algorithms","title":"Pattern 1: Added by Type","text":"","category":"section"},{"location":"user/referencing_algorithms/","page":"Referencing Algorithms","title":"Referencing Algorithms","text":"struct Producer <: ProcessAlgorithm end\nstruct Consumer <: ProcessAlgorithm end\n\nalgo = CompositeAlgorithm(\n    Producer, Consumer,\n    (1, 1),\n    Route(Producer => Consumer, :value),\n)","category":"page"},{"location":"user/referencing_algorithms/","page":"Referencing Algorithms","title":"Referencing Algorithms","text":"Use Producer and Consumer again when targeting these algorithms.","category":"page"},{"location":"user/referencing_algorithms/#Pattern-2:-Added-by-Instance","page":"Referencing Algorithms","title":"Pattern 2: Added by Instance","text":"","category":"section"},{"location":"user/referencing_algorithms/","page":"Referencing Algorithms","title":"Referencing Algorithms","text":"producer = Producer()\nconsumer = Consumer()\n\nalgo = CompositeAlgorithm(\n    producer, consumer,\n    (1, 1),\n    Route(producer => consumer, :value),\n)","category":"page"},{"location":"user/referencing_algorithms/","page":"Referencing Algorithms","title":"Referencing Algorithms","text":"Use producer and consumer again, not fresh Producer() calls.","category":"page"},{"location":"user/referencing_algorithms/#Pattern-3:-Added-with-Unique","page":"Referencing Algorithms","title":"Pattern 3: Added with Unique","text":"","category":"section"},{"location":"user/referencing_algorithms/","page":"Referencing Algorithms","title":"Referencing Algorithms","text":"producer_a = Producer()\nproducer_b = Unique(Producer())\nconsumer = Consumer()\n\nalgo = CompositeAlgorithm(\n    producer_a, producer_b, consumer,\n    (1, 1, 1),\n    Route(producer_b => consumer, :value),\n)","category":"page"},{"location":"user/referencing_algorithms/","page":"Referencing Algorithms","title":"Referencing Algorithms","text":"producer_b is a distinct identity. Keep that variable and reuse it anywhere you need to target that exact algorithm.","category":"page"},{"location":"user/referencing_algorithms/#Common-Mistake","page":"Referencing Algorithms","title":"Common Mistake","text":"","category":"section"},{"location":"user/referencing_algorithms/","page":"Referencing Algorithms","title":"Referencing Algorithms","text":"Do not create a new object in Route/Share/Input/Override unless that exact object was inserted in the composition.","category":"page"},{"location":"user/referencing_algorithms/","page":"Referencing Algorithms","title":"Referencing Algorithms","text":"Some immutable objects can match by equal value, but relying on that makes code harder to read. Reusing the original reference is the clearest rule.","category":"page"},{"location":"internals/registry/#registry_internals","page":"Registry","title":"Registry Internals","text":"","category":"section"},{"location":"internals/registry/","page":"Registry","title":"Registry","text":"The registry layer is what assigns stable subcontext names to algorithms/states and makes value/type lookups predictable.","category":"page"},{"location":"internals/registry/","page":"Registry","title":"Registry","text":"Core types:","category":"page"},{"location":"internals/registry/","page":"Registry","title":"Registry","text":"NameSpaceRegistry: top-level registry (src/Registry/StructDefs.jl).\nRegistryTypeEntry{T}: one partition per entry type (src/Registry/StructDefs.jl).\nIdentifiableAlgo{F,Id,...,Key}: wrapped process entity with identity and assigned context key (src/Identifiable/StructDef.jl).","category":"page"},{"location":"internals/registry/#1.-Type-Partitions-and-Matching","page":"Registry","title":"1. Type Partitions and Matching","text":"","category":"section"},{"location":"internals/registry/","page":"Registry","title":"Registry","text":"Entries are grouped by assign_entrytype(obj) (src/Registry/Traits.jl).","category":"page"},{"location":"internals/registry/","page":"Registry","title":"Registry","text":"Default entry type: the object's type wrapper.\nIdentifiableAlgo overrides this via registry_entrytype(::Type{<:IdentifiableAlgo{T}}) = T (src/Identifiable/IdentifiableAlgos.jl).","category":"page"},{"location":"internals/registry/","page":"Registry","title":"Registry","text":"Within each RegistryTypeEntry, matches use match_by (src/Matching.jl, src/ProcessEntities/Matching.jl):","category":"page"},{"location":"internals/registry/","page":"Registry","title":"Registry","text":"Process entity instance (Fib()): direct immutable instances match by value; other instances match by object identity.\nProcess entity type (Fib): matches by type (match_by(::Type{<:ProcessEntity}) = T).","category":"page"},{"location":"internals/registry/","page":"Registry","title":"Registry","text":"This is why instance-based and type-based registrations are distinct identities.","category":"page"},{"location":"internals/registry/#2.-Key-Assignment","page":"Registry","title":"2. Key Assignment","text":"","category":"section"},{"location":"internals/registry/","page":"Registry","title":"Registry","text":"add(reg, obj, multiplier) (src/Registry/Registries.jl, src/Registry/TypeEntries.jl) does:","category":"page"},{"location":"internals/registry/","page":"Registry","title":"Registry","text":"Find/create the correct RegistryTypeEntry.\nIf no match exists, create a key with Autokey (TypeName_index) and wrap as IdentifiableAlgo.\nIf a match exists, reuse the existing key and increase multiplier.","category":"page"},{"location":"internals/registry/","page":"Registry","title":"Registry","text":"Key consequences:","category":"page"},{"location":"internals/registry/","page":"Registry","title":"Registry","text":"Same value entered repeatedly: same key reused.\nSame type entered repeatedly: same key reused for that type identity.\nType-entered value vs value-entered value can still be different identities.\nThis stays true across nested CompositeAlgorithm/Routine trees because setup_registry flattens all entities into one registry pass before context creation.","category":"page"},{"location":"internals/registry/#3.-Unique-and-Distinguishability","page":"Registry","title":"3. Unique and Distinguishability","text":"","category":"section"},{"location":"internals/registry/","page":"Registry","title":"Registry","text":"Unique(f) builds an IdentifiableAlgo with a fresh UUID identity (src/Identifiable/StructDef.jl).","category":"page"},{"location":"internals/registry/","page":"Registry","title":"Registry","text":"That gives a guaranteed distinct match identity even when the wrapped value is otherwise indistinguishable.","category":"page"},{"location":"internals/registry/","page":"Registry","title":"Registry","text":"This is the mechanism used when you need multiple logically separate instances of the same algorithm in one composition.","category":"page"},{"location":"internals/registry/#4.-Lookup-Behavior","page":"Registry","title":"4. Lookup Behavior","text":"","category":"section"},{"location":"internals/registry/","page":"Registry","title":"Registry","text":"ProcessContext lookups by value/type eventually call registry getindex (src/Context/ProcessContexts.jl, src/Registry/Registries.jl).","category":"page"},{"location":"internals/registry/","page":"Registry","title":"Registry","text":"The registry also supports direct symbol-key lookup:","category":"page"},{"location":"internals/registry/","page":"Registry","title":"Registry","text":"reg[:Fib_1] returns the registered IdentifiableAlgo","category":"page"},{"location":"internals/registry/","page":"Registry","title":"Registry","text":"That is the same key space used by:","category":"page"},{"location":"internals/registry/","page":"Registry","title":"Registry","text":"resolved[:Fib_1] on resolved loop algorithms\nctx[:Fib_1] on process contexts","category":"page"},{"location":"internals/registry/","page":"Registry","title":"Registry","text":"Important runtime detail in NameSpaceRegistry.getindex:","category":"page"},{"location":"internals/registry/","page":"Registry","title":"Registry","text":"Type, direct immutable values, and AbstractIdentifiableAlgo values use the static lookup path.\nother values use the dynamic lookup table keyed by match_by(obj).","category":"page"},{"location":"internals/registry/","page":"Registry","title":"Registry","text":"So direct immutable instances can match equal values, while ordinary mutable instances match by object identity. Unique(...) gives an explicit fresh identity when the default rules are not what you want.","category":"page"},{"location":"internals/registry/#5.-Multipliers","page":"Registry","title":"5. Multipliers","text":"","category":"section"},{"location":"internals/registry/","page":"Registry","title":"Registry","text":"Each registry entry tracks a multiplier (RegistryTypeEntry.multipliers).","category":"page"},{"location":"internals/registry/","page":"Registry","title":"Registry","text":"For loop algorithms this is derived from composition structure (intervals/repeats), and is used by utilities such as processsizehint!/num_calls (src/Tools.jl).","category":"page"},{"location":"internals/registry/#6.-Order-Guarantees","page":"Registry","title":"6. Order Guarantees","text":"","category":"section"},{"location":"internals/registry/","page":"Registry","title":"Registry","text":"setup_registry adds:","category":"page"},{"location":"internals/registry/","page":"Registry","title":"Registry","text":"ProcessStates first.\nThen flattened algorithms.","category":"page"},{"location":"internals/registry/","page":"Registry","title":"Registry","text":"(see src/LoopAlgorithms/Setup.jl)","category":"page"},{"location":"internals/registry/","page":"Registry","title":"Registry","text":"That ordering controls init/cleanup traversal order through all_algos(registry).","category":"page"},{"location":"internals/process_pipeline/#process_pipeline_internals","page":"Process Pipeline","title":"Process Pipeline Internals","text":"","category":"section"},{"location":"internals/process_pipeline/","page":"Process Pipeline","title":"Process Pipeline","text":"This page documents the runtime path from loop algorithm construction to loop execution.","category":"page"},{"location":"internals/process_pipeline/#1.-Construction","page":"Process Pipeline","title":"1. Construction","text":"","category":"section"},{"location":"internals/process_pipeline/","page":"Process Pipeline","title":"Process Pipeline","text":"Process(func, inputs_overrides...; repeats, lifetime, timeout) (src/Process.jl):","category":"page"},{"location":"internals/process_pipeline/","page":"Process Pipeline","title":"Process Pipeline","text":"Wrap bare ProcessAlgorithm as a one-child CompositeAlgorithm.\nNormalize stop behavior: repeats = n becomes Repeat(n), lifetime accepts Lifetime objects, and Routine defaults to Repeat(1) when no lifetime is provided.\nResolve the loop algorithm when needed.\nRun lifecycle init(algo, specs...; lifetime) unless an initialized context is already provided.\nStore the algorithm and its current runtime context on the process.","category":"page"},{"location":"internals/process_pipeline/","page":"Process Pipeline","title":"Process Pipeline","text":"There is no TaskData layer. The initialized loop algorithm carries the persistent context plus stored init/override specs. Process keeps its current context separately so pausing can preserve a suspended runtime context without rebaking it into the algorithm.","category":"page"},{"location":"internals/process_pipeline/#2.-Init-Phase","page":"Process Pipeline","title":"2. Init Phase","text":"","category":"section"},{"location":"internals/process_pipeline/","page":"Process Pipeline","title":"Process Pipeline","text":"init(la::LoopAlgorithm, specs...) (src/LoopAlgorithms/RuntimeInputs.jl) applies:","category":"page"},{"location":"internals/process_pipeline/","page":"Process Pipeline","title":"Process Pipeline","text":"Resolve Init/Override specs through the registry.\nMerge passed specs over stored specs per target.\nBuild a fresh persistent ProcessContext with algo and lifetime in _runtime.\nMerge Init values into target subcontexts.\nRun init(algo, input_context).\nMerge Override values after init.\nReturn a loop algorithm with stored context, inits, and overrides.","category":"page"},{"location":"internals/process_pipeline/","page":"Process Pipeline","title":"Process Pipeline","text":"For loop algorithms, init(::LoopAlgorithm, ::ProcessContext) iterates all registry entities in order (src/LoopAlgorithms/Init.jl).","category":"page"},{"location":"internals/process_pipeline/","page":"Process Pipeline","title":"Process Pipeline","text":"partialinit(la, specs...) uses the same target resolution but only rebuilds the targeted subcontexts.","category":"page"},{"location":"internals/process_pipeline/#3.-Running","page":"Process Pipeline","title":"3. Running","text":"","category":"section"},{"location":"internals/process_pipeline/","page":"Process Pipeline","title":"Process Pipeline","text":"run(p; kwargs...) (src/ProcessInteraction.jl) calls makeloop! (src/Process.jl).","category":"page"},{"location":"internals/process_pipeline/","page":"Process Pipeline","title":"Process Pipeline","text":"makeloop!:","category":"page"},{"location":"internals/process_pipeline/","page":"Process Pipeline","title":"Process Pipeline","text":"validates runtime keyword arguments against the loop algorithm's @input metadata,\npasses the persistent context to loop,\npasses runtime inputs as a positional NamedTuple to loop,\nspawns the loop task.","category":"page"},{"location":"internals/process_pipeline/","page":"Process Pipeline","title":"Process Pipeline","text":"run(la::LoopAlgorithm; kwargs...) runs an initialized loop algorithm directly and returns a loop algorithm with the next persistent context.","category":"page"},{"location":"internals/process_pipeline/#4.-Loop-Bootstrap-and-Runtime-Inputs","page":"Process Pipeline","title":"4. Loop Bootstrap and Runtime Inputs","text":"","category":"section"},{"location":"internals/process_pipeline/","page":"Process Pipeline","title":"Process Pipeline","text":"The loop wrappers in src/Loops.jl merge runtime inputs before the while/for loop:","category":"page"},{"location":"internals/process_pipeline/","page":"Process Pipeline","title":"Process Pipeline","text":"loop(process, algo, context, lifetime, inputs)","category":"page"},{"location":"internals/process_pipeline/","page":"Process Pipeline","title":"Process Pipeline","text":"The loop injects process and lifetime into the transient _runtime field. An empty input tuple is a no-op. A non-empty tuple is merged into the transient ProcessContext._input field. The bootstrap/first step may change the transient context type. After bootstrap, steady-state steps must preserve context type.","category":"page"},{"location":"internals/process_pipeline/","page":"Process Pipeline","title":"Process Pipeline","text":"Repeat and indefinite loops are defined in src/Loops.jl; generated loops live in src/GeneratedCode/GeneratedLoops.jl.","category":"page"},{"location":"internals/process_pipeline/","page":"Process Pipeline","title":"Process Pipeline","text":"High-level structure:","category":"page"},{"location":"internals/process_pipeline/","page":"Process Pipeline","title":"Process Pipeline","text":"before_while(process)\none unstable/bootstrap step\nrepeat/while body with stable step calls\ntick/index increments\nafter_while(process, algo, context, stored_context)","category":"page"},{"location":"internals/process_pipeline/","page":"Process Pipeline","title":"Process Pipeline","text":"Step bodies are produced by step!_expr (src/LoopAlgorithms/GeneratedStep.jl and src/Identifiable/Step.jl) so composite/routine structures can be unrolled and specialized to concrete algorithm/context types.","category":"page"},{"location":"internals/process_pipeline/#5.-Cleanup-Behavior","page":"Process Pipeline","title":"5. Cleanup Behavior","text":"","category":"section"},{"location":"internals/process_pipeline/","page":"Process Pipeline","title":"Process Pipeline","text":"after_while (src/Loops.jl) does:","category":"page"},{"location":"internals/process_pipeline/","page":"Process Pipeline","title":"Process Pipeline","text":"paused process: store the suspended runtime context as a side effect, but compute the task result from the stripped persistent context shape.\ninterrupted or indefinite: strip runtime-only fields before computing the task result.\nnatural finite completion: store cleanup(func, context) stripped back to persistent context shape, then compute the task result.","category":"page"},{"location":"internals/process_pipeline/","page":"Process Pipeline","title":"Process Pipeline","text":"Finished Process, InlineProcess, and direct run(la::LoopAlgorithm) paths store contexts that may be absorbed back into an algorithm, so runtime-only fields such as _input, process, and lifetime are stripped. A paused Process may still keep the live runtime context internally so it can resume. For ordinary algorithms the task result is the stripped context. For FinalizedAlgorithm, the final function projects a result from that stripped context, so fetch(process) still returns the @finally value.","category":"page"},{"location":"internals/process_pipeline/","page":"Process Pipeline","title":"Process Pipeline","text":"Paused processes resume through the normal loop path with a Resuming{true} entry trait. Fresh runs use Resuming{false}. This keeps the bootstrap decision in dispatch, so fresh runs infer the post-bootstrap context type and resumed runs infer the already-grown context type. New runtime inputs, init specs, and lifetime changes are rejected while resuming.","category":"page"},{"location":"internals/process_pipeline/#6.-Open-Discovery-Phase-Need","page":"Process Pipeline","title":"6. Open Discovery Phase Need","text":"","category":"section"},{"location":"internals/process_pipeline/","page":"Process Pipeline","title":"Process Pipeline","text":"Some future process algorithms may need type discovery after lifecycle init has run and after routes are known, but before normal scheduled stepping begins. This should not become public bootstrap API: the bootstrap/unsafe step remains loop-owned, and transient values created only to discover route shapes should be discarded after the run.","category":"page"},{"location":"internals/process_pipeline/","page":"Process Pipeline","title":"Process Pipeline","text":"The intended future direction is a small route-aware discovery phase exposed through the @ProcessAlgorithm API. That phase would let an algorithm declare or compute first-step value shapes without requiring its scheduled step! to run early. Until that exists, delayed algorithms that expose values to other steps must initialize those values in persistent state or be wrapped in a routine/composition whose first scheduled step makes the value available before consumers run.","category":"page"},{"location":"internals/routes_shares/#routes_shares_internals","page":"Routes and Shares","title":"Routes and Shares Internals","text":"","category":"section"},{"location":"internals/routes_shares/","page":"Routes and Shares","title":"Routes and Shares","text":"Route and Share are plan options. Resolution happens when a plan is wrapped and resolved as a concrete LoopAlgorithm.","category":"page"},{"location":"internals/routes_shares/","page":"Routes and Shares","title":"Routes and Shares","text":"Relevant files:","category":"page"},{"location":"internals/routes_shares/","page":"Routes and Shares","title":"Routes and Shares","text":"Definitions: src/RoutingInterface/RouteDef.jl, src/RoutingInterface/ShareDef.jl\nResolution backend: src/RoutingInterface/Resolving.jl, src/RoutingInterface/Backend.jl, src/RoutingInterface/Sharing.jl\nPlan integration: src/LoopAlgorithms/PlanOptions.jl, src/LoopAlgorithms/Preparation/Constructor.jl\nView integration: src/Context/View/StructDef.jl, src/Context/View/Locations.jl","category":"page"},{"location":"internals/routes_shares/#1.-Route-Resolution","page":"Routes and Shares","title":"1. Route Resolution","text":"","category":"section"},{"location":"internals/routes_shares/","page":"Routes and Shares","title":"Routes and Shares","text":"Route stores:","category":"page"},{"location":"internals/routes_shares/","page":"Routes and Shares","title":"Routes and Shares","text":"source endpoint (from)\ntarget endpoint (to)\nrouted source variable names\nlocal aliases in target view\noptional transform function\noptional reverse transform function\nprecomputed match_by identities for from/to","category":"page"},{"location":"internals/routes_shares/","page":"Routes and Shares","title":"Routes and Shares","text":"resolve_options(reg, routes...) converts each route into:","category":"page"},{"location":"internals/routes_shares/","page":"Routes and Shares","title":"Routes and Shares","text":"target subcontext name => tuple of resolved Route metadata, including source names, target aliases, transform, and reverse transform.","category":"page"},{"location":"internals/routes_shares/","page":"Routes and Shares","title":"Routes and Shares","text":"to_sharedvar resolves endpoints by matcher identity in the registry, then binds concrete source/target keys.","category":"page"},{"location":"internals/routes_shares/","page":"Routes and Shares","title":"Routes and Shares","text":"Transform details:","category":"page"},{"location":"internals/routes_shares/","page":"Routes and Shares","title":"Routes and Shares","text":"Route(...; transform = f) or Route(...; reverse_transform = g) is restricted to exactly one mapping entry.\nThat single mapping can still be multi-source by mapping (:a, :b, ...) => :local_name.\nAt view-read time this becomes a VarLocation with tuple originalname and func = f, so the generated getter reads each source variable and calls f(a, b, ...).\nAt writeback time, transformed route aliases must have a reverse transform. Multi-source reverse transforms can return a tuple in source-variable order or a named tuple keyed by source variable name.","category":"page"},{"location":"internals/routes_shares/#2.-Share-Resolution","page":"Routes and Shares","title":"2. Share Resolution","text":"","category":"section"},{"location":"internals/routes_shares/","page":"Routes and Shares","title":"Routes and Shares","text":"Share(a,b; directional=false) is converted to SharedContext metadata:","category":"page"},{"location":"internals/routes_shares/","page":"Routes and Shares","title":"Routes and Shares","text":"a -> b\nand also b -> a when non-directional.","category":"page"},{"location":"internals/routes_shares/","page":"Routes and Shares","title":"Routes and Shares","text":"This metadata is attached to the target child's StepRouting.","category":"page"},{"location":"internals/routes_shares/#3.-How-Views-See-Them","page":"Routes and Shares","title":"3. How Views See Them","text":"","category":"section"},{"location":"internals/routes_shares/","page":"Routes and Shares","title":"Routes and Shares","text":"When creating SubContextView locations (src/Context/View/Locations.jl):","category":"page"},{"location":"internals/routes_shares/","page":"Routes and Shares","title":"Routes and Shares","text":"SharedContext contributes all variables from the shared subcontext.\nRoute metadata contributes only specified routed vars, plus transform and reverse transform if provided.","category":"page"},{"location":"internals/routes_shares/","page":"Routes and Shares","title":"Routes and Shares","text":"Both become VarLocation{:subcontext} entries, so reads and writes are directed to the source subcontext.","category":"page"},{"location":"internals/routes_shares/","page":"Routes and Shares","title":"Routes and Shares","text":"That means returning a routed/shared variable from step! can update remote state, not only local state.","category":"page"},{"location":"internals/routes_shares/","page":"Routes and Shares","title":"Routes and Shares","text":"The view constructor reconstructs resolved route/share tuples from their concrete tuple types. The runtime routing value selects the type-specialized view, but the view does not depend on const-propagating route/share values.","category":"page"},{"location":"internals/routes_shares/#4.-Errors-and-Validation","page":"Routes and Shares","title":"4. Errors and Validation","text":"","category":"section"},{"location":"internals/routes_shares/","page":"Routes and Shares","title":"Routes and Shares","text":"If route/share endpoints are not present in the registry, resolution throws explicit errors listing available keys (see to_sharedvar and to_sharedcontext).","category":"page"},{"location":"internals/routes_shares/#5.-Relation-to-Packaging","page":"Routes and Shares","title":"5. Relation to Packaging","text":"","category":"section"},{"location":"internals/routes_shares/","page":"Routes and Shares","title":"Routes and Shares","text":"During Package(comp), routes are translated into VarAliases for internal subpackages (src/Packaging/Constructor.jl, src/Packaging/Utils.jl).","category":"page"},{"location":"internals/routes_shares/#6.-Plan-Local-Wiring","page":"Routes and Shares","title":"6. Plan-Local Wiring","text":"","category":"section"},{"location":"internals/routes_shares/","page":"Routes and Shares","title":"Routes and Shares","text":"Plain Route/Share options are stored on the plan node that contains them. DSL-local route/share statements become child-aligned local wiring, so the resolved StepRouting passed to a child is specific to that child location.","category":"page"},{"location":"internals/routes_shares/","page":"Routes and Shares","title":"Routes and Shares","text":"Nested plan routes remain local to the nested plan. A route/share assigned to a nested plan child itself is rejected because nested plan nodes do not have their own root context key; attach that route/share to a concrete child inside the nested plan instead.","category":"page"},{"location":"internals/routes_shares/","page":"Routes and Shares","title":"Routes and Shares","text":"If both top-level and local routes expose the same target alias, local routes take precedence for that child step.","category":"page"},{"location":"user/threaded_process_managers/#threaded_process_managers_user","page":"Threaded Process Managers","title":"Process Managers","text":"","category":"section"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"Use a ProcessManager when you already have a worker definition and want to run many independent jobs through a bounded set of reusable workers. For normal Processes.jl usage, each worker is usually a reusable Process, but managers can also wrap custom worker objects.","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"The current manager API separates two ideas:","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"a portable recipe core that describes how one job is loaded, run, read, and synchronized;\nan execution mode stored on the manager that decides how workers are scheduled.","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"manager = ProcessManager(recipe; nworkers = 4, execution = ThreadedWorkers(Dynamic()))\nrun!(manager, jobs)","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"Do not pass execution modes to run!. Construct the manager with the execution mode you want, then call run!(manager, jobs).","category":"page"},{"location":"user/threaded_process_managers/#Terms","page":"Threaded Process Managers","title":"Terms","text":"","category":"section"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"A job is one item of work, such as one sample, trajectory, or simulation case.\nA worker is the reusable object that handles one job at a time.\nA slot is the manager record around one worker. It stores the worker, the current job, the latest result, and the latest error.\nA recipe tells the manager how to create workers and how each job should interact with one worker.\nmanager.state is manager-owned runtime data, commonly used for output buffers, counters, shared parameters, and optimizer state.","category":"page"},{"location":"user/threaded_process_managers/#Portable-Recipe-Core","page":"Threaded Process Managers","title":"Portable Recipe Core","text":"","category":"section"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"The standard lifecycle calls these recipe callbacks:","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"loadjob!(recipe, slot, job, manager)\nprovidearguments(recipe, slot, job, manager)\nafterjob!(recipe, slot, job, manager)\nsync_to_state!(recipe, manager)","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"As named tuple fields:","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"recipe = (;\n    makeworker = (idx, manager) -> Process(MyAlgo; repeats = 1),\n\n    loadjob! = (slot, job, manager) -> begin\n        ctx = context(slot.worker)[MyAlgo]\n        ctx.value[] = job.value\n        resetworker!(slot)\n    end,\n\n    providearguments = (slot, job, manager) -> (;),\n\n    afterjob! = (slot, job, manager) -> begin\n        ctx = context(slot.worker)[MyAlgo]\n        push!(ctx.local_outputs, ctx.output[])\n    end,\n\n    sync_to_state! = manager -> begin\n        for slot in slots(manager)\n            ctx = context(slot.worker)[MyAlgo]\n            append!(manager.state.outputs, ctx.local_outputs)\n            empty!(ctx.local_outputs)\n        end\n    end,\n)","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"loadjob! is the normal place to write job data into context(slot.worker) and reset the worker. providearguments returns runtime keyword arguments for the worker run; return nothing or omit it if no runtime arguments are needed. afterjob! reads one finished worker. sync_to_state! merges worker-local state into manager.state or another shared destination according to the manager's sync policy.","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"The standard lifecycle does not fall back to old names such as prepare!, runarguments, consume!, or flush!. Those names are kept only as compatibility lookup functions and should not be used for new portable recipes.","category":"page"},{"location":"user/threaded_process_managers/#Execution-Modes","page":"Threaded Process Managers","title":"Execution Modes","text":"","category":"section"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"Execution mode is stored on the manager:","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"ProcessManager(recipe; execution = PollingWorkers())\nProcessManager(recipe; execution = ThreadedWorkers(Dynamic()))\nProcessManager(recipe; execution = ThreadedWorkers(Static()))\nProcessManager(recipe; execution = ThreadedWorkers(Greedy()))\nProcessManager(recipe; execution = ChannelWorkers(; channel_size = 8))","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"If execution is omitted, the manager uses PollingWorkers(). A recipe can also provide a default execution field:","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"recipe = (;\n    execution = ChannelWorkers(),\n    makeworker = (idx, manager) -> Process(MyAlgo; repeats = 1),\n    loadjob! = (slot, job, manager) -> nothing,\n)\n\nmanager = ProcessManager(recipe)","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"PollingWorkers() uses the original dispatch/poll/drain scheduler. ThreadedWorkers(schedule) runs jobs through Threads.@threads and runs default Process workers inline to avoid one task spawn per job. ChannelWorkers() starts one long-lived worker task per slot and lets workers pull jobs from a channel until the job stream closes.","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"run!(manager, jobs, Dynamic()), run!(manager, jobs, Static()), run!(manager, jobs, Greedy()), and run!(manager, jobs, ChannelWorkers()) throw an ArgumentError. Put the mode in ProcessManager(...; execution = ...) instead.","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"The direct helpers runthreaded! and runchannel! remain available as lower level escape hatches, but normal user-facing code should prefer manager-owned execution and plain run!(manager, jobs).","category":"page"},{"location":"user/threaded_process_managers/#Sync-Policies","page":"Threaded Process Managers","title":"Sync Policies","text":"","category":"section"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"sync_policy controls when sync_to_state!(recipe, manager) is called:","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"ProcessManager(recipe; sync_policy = SyncAtEnd())\nProcessManager(recipe; sync_policy = NoSync())\nProcessManager(recipe; sync_policy = SyncEvery(32; drain = true))","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"SyncAtEnd() is the default. It runs all jobs, drains active workers, then calls sync_to_state! once.\nNoSync() never calls sync_to_state! automatically.\nSyncEvery(n; drain = true) calls sync_to_state! after every n completed worker runs. With drain = true, active workers are finalized before syncing.","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"Use afterjob! for per-job result reads. Use sync_to_state! when results or worker-local buffers should be merged in batches.","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"The old names FlushAtEnd, NoFlush, FlushEvery, and the constructor keyword flush_policy are compatibility aliases. New code should use SyncAtEnd, NoSync, SyncEvery, and sync_policy.","category":"page"},{"location":"user/threaded_process_managers/#Manager-State","page":"Threaded Process Managers","title":"Manager State","text":"","category":"section"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"manager.state is shared manager-owned data. Worker context is slot-local:","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"use manager.state for shared parameters, output buffers, counters, optimizer state, and history;\nuse context(slot.worker) for the current job, worker-local buffers, and temporary state.","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"Build manager state with initstate:","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"recipe = (;\n    initstate = config -> (;\n        params = Ref(config.initial_params),\n        outputs = Float64[],\n    ),\n    makeworker = (idx, manager) -> Process(MyAlgo; repeats = 1),\n)\n\nmanager = ProcessManager(\n    recipe;\n    config = (; initial_params = (w = 0.0, b = 0.0)),\n)","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"or pass it directly:","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"manager = ProcessManager(recipe; state = (; outputs = Float64[]))","category":"page"},{"location":"user/threaded_process_managers/#Worker-Ownership","page":"Threaded Process Managers","title":"Worker Ownership","text":"","category":"section"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"The usual form lets the manager create and own workers:","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"recipe = (;\n    makeworker = (idx, manager) -> Process(MyAlgo; repeats = 1),\n    loadjob! = (slot, job, manager) -> begin\n        ctx = context(slot.worker)[MyAlgo]\n        ctx.value[] = job.value\n        resetworker!(slot)\n    end,\n)\n\nmanager = ProcessManager(recipe; nworkers = 4)","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"If workers = ... is passed, the manager wraps existing workers and does not create new contexts:","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"manager = ProcessManager(recipe; workers = existing_workers)","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"For manager-owned Process workers, makecontext can build separate per-slot contexts while sharing one worker template:","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"recipe = (;\n    makeworker = (idx, manager) -> Process(MyAlgo; repeats = 1),\n    makecontext = (idx, manager, template) -> begin\n        initialized = init(getalgo(template), Init(MyAlgo; seed = idx))\n        context(initialized)\n    end,\n)","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"Inspect slots and workers with:","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"slots(manager)\nworkers(manager)","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"Closing an owning manager closes its workers:","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"close(manager)","category":"page"},{"location":"user/threaded_process_managers/#On-Demand-Workers","page":"Threaded Process Managers","title":"On-Demand Workers","text":"","category":"section"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"Use OnDemandWorkers() when each job should construct its own worker:","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"recipe = (;\n    initstate = config -> (; results = []),\n    workername = (idx, manager, job) -> job.name,\n    makeworker = (idx, manager, job) -> Process(\n        job.algo,\n        Init(job.algo; seed = job.seed);\n        repeats = 1,\n    ),\n    afterjob! = (slot, job, manager) -> push!(\n        manager.state.results,\n        (; name = slot.name, output = job.readout(slot.worker)),\n    ),\n)\n\nmanager = ProcessManager(\n    recipe;\n    nworkers = 4,\n    worker_lifecycle = OnDemandWorkers(destroy_after_finalize = false),\n    worker_type = Process,\n)","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"Pass worker_type when different jobs may return different concrete worker types. Use destroy_after_finalize = false if the last finished worker should remain in the slot for inspection.","category":"page"},{"location":"user/threaded_process_managers/#Execution-Specific-Hooks","page":"Threaded Process Managers","title":"Execution-Specific Hooks","text":"","category":"section"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"The portable recipe core works across polling, threaded, and channel execution modes. Advanced callbacks can take over parts of the execution protocol:","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"start!(slot, job, manager) replaces the default worker launch.\nisdone(slot, manager) customizes polling completion checks.\nfinalize!(slot, job, manager) replaces default worker finalization.\nworkerfinalizer(slot, job, manager) chooses a per-job finalizer.","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"These hooks are execution-specific. In particular, isdone is valid only with PollingWorkers(), because threaded and channel workers own the job until it is complete and do not poll per-job completion.","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"For normal result accumulation, prefer afterjob! over finalize!. Use finalize! only when worker finalization itself must be customized.","category":"page"},{"location":"user/threaded_process_managers/#Runtime-Inputs-And-Reinitialization","page":"Threaded Process Managers","title":"Runtime Inputs And Reinitialization","text":"","category":"section"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"Use loadjob! for persistent context changes:","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"loadjob! = (slot, job, manager) -> begin\n    ctx = context(slot.worker)[MyAlgo]\n    ctx.value[] = job.value\n    resetworker!(slot)\nend","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"Use providearguments for loop-level runtime @input values:","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"providearguments = (slot, job, manager) -> (; temperature = job.temperature)","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"For Process workers, lifetime, repeats, and repeat returned by providearguments are launch controls. Other keys are passed as runtime inputs.","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"Use reinitworker! when the whole worker context should be rebuilt through the normal init pipeline:","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"loadjob! = (slot, job, manager) -> reinitworker!(\n    slot,\n    Input(MyAlgo, :start => job.start),\n)","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"Use partialinitworker! when only selected context targets should be rebuilt:","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"loadjob! = (slot, job, manager) -> partialinitworker!(\n    slot,\n    Init(MyStep; base = job.base),\n)","category":"page"},{"location":"user/threaded_process_managers/#Chunked-Inline-Workers","page":"Threaded Process Managers","title":"Chunked Inline Workers","text":"","category":"section"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"runchunks! remains a specialized batching path for InlineChunkWorker. It is not part of the portable manager recipe core. Chunked recipes keep their chunk-specific callback names:","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"beforechunk!\nresetexample!\nloadexample!\nafterexample!\nafterchunk!","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"Use chunked inline workers when a chunk is semantically meaningful or when an InlineProcess should process many examples inside one manager job. If the goal is only to avoid per-job task spawning for ordinary Process workers, prefer ChannelWorkers() or ThreadedWorkers(...).","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"worker = InlineChunkWorker(InlineProcess(MyInlineAlgo; repeats = 1))\n\nmanager = ProcessManager(\n    recipe;\n    workers = (worker,),\n    sync_policy = NoSync(),\n    job_type = Vector{Int},\n)\n\nrunchunks!(manager, dataset; chunksize = 128)","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"Threaded chunk scheduling still accepts a thread schedule directly:","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"runchunks!(manager, dataset, Dynamic(); chunksize = 128)\nrunchunks!(manager, dataset, Static(); chunksize = 128)\nrunchunks!(manager, dataset, Greedy(); chunksize = 128)","category":"page"},{"location":"user/threaded_process_managers/#Public-API-Reference","page":"Threaded Process Managers","title":"Public API Reference","text":"","category":"section"},{"location":"user/threaded_process_managers/#Processes.ProcessManager","page":"Threaded Process Managers","title":"Processes.ProcessManager","text":"ProcessManager(recipe; nworkers = Threads.nthreads(), workers = nothing,\n               config = nothing, state = nothing,\n               sync_policy = SyncAtEnd(), flush_policy = nothing,\n               execution = nothing,\n               worker_lifecycle = ReuseWorker(),\n               worker_init = CopyFirstWorker(),\n               worker_init_data = nothing,\n               worker_type = nothing,\n               name_type = Symbol,\n               throw = true, poll_interval = 0.0,\n               job_type = Any, scratch_type = Any,\n               result_type = Any, error_type = Any)\n\nFlexible worker orchestrator.\n\nRecipes may be named tuples containing callbacks, or concrete objects that overload the callback functions below. The default worker protocol supports Process workers.\n\nFor each job, the portable lifecycle assigns a free slot, calls loadjob!, calls providearguments, runs the worker through the manager's execution mode, finalizes the worker, calls afterjob!, and eventually calls sync_to_state! according to the manager's sync policy.\n\nWhen workers is omitted, the recipe must define makeworker. The manager calls makeworker once to create a template worker, then copies that template for the remaining slots. The default Process copy reuses the template task description and deep-copies the runtime context. Recipes can define makecontext(idx, manager, template) to build a separate Process context for each slot while keeping the template task description, or copyworker(template, idx, manager) when the whole worker copy must be custom. When workers is passed, the manager wraps those existing workers in slots and does not create new worker contexts.\n\nSet worker_init = MakeEachWorker() to call makeworker(idx, manager) for every owned slot instead of copying slot 1. This avoids the manager's deepcopy-based default Process copy path entirely. Pass worker_init_data = data to provide one value per worker; callbacks may accept it as makeworker(idx, manager, data).\n\nUse worker_lifecycle = OnDemandWorkers() when workers should be constructed from job data instead of upfront. That mode lives in OnDemandWorkers.jl and uses makeworker(idx, manager, job) for each dispatched job. Pass worker_type when the job may choose among different concrete worker types.\n\nSlots have a public name field for logs and result lookup. Missing workername callbacks use names such as :worker_1. Pass name_type if names should use a type other than Symbol.\n\nThe job_type, scratch_type, result_type, and error_type keywords let latency-sensitive code make worker slot fields concrete. Leaving them as Any keeps the manager fully flexible.\n\n\n\n\n\n","category":"type"},{"location":"user/threaded_process_managers/#Processes.WorkerSlot","page":"Threaded Process Managers","title":"Processes.WorkerSlot","text":"WorkerSlot\n\nTransparent manager-owned slot around a reusable worker.\n\nThe worker field is intentionally public so recipes can inspect and mutate the underlying worker context directly.\n\n\n\n\n\n","category":"type"},{"location":"user/threaded_process_managers/#Processes.PollingWorkers","page":"Threaded Process Managers","title":"Processes.PollingWorkers","text":"PollingWorkers()\n\nRun the manager through the default polling scheduler, which starts worker jobs and polls active slots for completion.\n\n\n\n\n\n","category":"type"},{"location":"user/threaded_process_managers/#Processes.ThreadedWorkers","page":"Threaded Process Managers","title":"Processes.ThreadedWorkers","text":"ThreadedWorkers(schedule = Dynamic())\n\nRun jobs through a threaded scheduler using schedule.\n\n\n\n\n\n","category":"type"},{"location":"user/threaded_process_managers/#Processes.ChannelWorkers","page":"Threaded Process Managers","title":"Processes.ChannelWorkers","text":"ChannelWorkers(; channel_size = nothing)\nChannelWorkers(channel_size)\n\nManager execution mode that starts one long-lived worker task per slot and has those workers pull jobs from a channel until it closes. When channel_size is nothing, the internal channel uses one slot per manager worker.\n\n\n\n\n\n","category":"type"},{"location":"user/threaded_process_managers/#Processes.SyncAtEnd","page":"Threaded Process Managers","title":"Processes.SyncAtEnd","text":"SyncAtEnd()\n\nSynchronize worker-local state once, after all dispatched work has drained.\n\n\n\n\n\n","category":"type"},{"location":"user/threaded_process_managers/#Processes.NoSync","page":"Threaded Process Managers","title":"Processes.NoSync","text":"NoSync()\n\nNever invoke the recipe sync_to_state! callback automatically.\n\n\n\n\n\n","category":"type"},{"location":"user/threaded_process_managers/#Processes.SyncEvery","page":"Threaded Process Managers","title":"Processes.SyncEvery","text":"SyncEvery(n; drain = true)\n\nInvoke the recipe sync_to_state! callback after every n completed worker runs. When drain is true, all active workers are finalized before syncing.\n\n\n\n\n\n","category":"type"},{"location":"user/threaded_process_managers/#Processes.loadjob!","page":"Threaded Process Managers","title":"Processes.loadjob!","text":"loadjob!(recipe, slot, job, manager)\n\nPortable per-job callback that loads job into worker-local state before the worker is run.\n\n\n\n\n\n","category":"function"},{"location":"user/threaded_process_managers/#Processes.providearguments","page":"Threaded Process Managers","title":"Processes.providearguments","text":"providearguments(recipe, slot, job, manager)\n\nPortable per-job callback that returns runtime keyword arguments for the implicit worker launch. Return a NamedTuple for run(slot.worker; kwargs...), or return nothing for no runtime keyword arguments.\n\n\n\n\n\n","category":"function"},{"location":"user/threaded_process_managers/#Processes.afterjob!","page":"Threaded Process Managers","title":"Processes.afterjob!","text":"afterjob!(recipe, slot, job, manager)\n\nPortable per-job callback for reading a finished worker and accumulating worker-local results.\n\n\n\n\n\n","category":"function"},{"location":"user/threaded_process_managers/#Processes.sync_to_state!","page":"Threaded Process Managers","title":"Processes.sync_to_state!","text":"sync_to_state!(recipe, manager)\n\nPortable manager-level callback controlled by the manager's SyncPolicy.\n\nThe manager calls this only after one or more worker runs have completed. It is the usual place to merge per-worker buffers into shared manager state, apply one batched parameter update, write accumulated results to an external destination, or clear worker-local accumulation buffers for the next batch of jobs.\n\nsync_to_state! is not called per job. Its timing depends on sync_policy:\n\nSyncAtEnd(): once after the run finishes.\nSyncEvery(n; drain = true): after every n completed runs, with optional draining of active slots first.\nNoSync(): never called automatically.\n\n\n\n\n\n","category":"function"},{"location":"user/threaded_process_managers/#Processes.run!","page":"Threaded Process Managers","title":"Processes.run!","text":"run!(manager, jobs)\n\nRun jobs using the execution mode stored on manager.\n\n\n\n\n\nrun!(manager, jobs, mode)\n\nExecution modes are manager-owned. Construct the manager with execution = mode instead of passing a mode to run!.\n\n\n\n\n\nrun!(manager, jobs, schedule)\n\nExecution schedules are manager-owned through ThreadedWorkers(schedule).\n\n\n\n\n\n","category":"function"},{"location":"user/threaded_process_managers/#Processes.runchannel!","page":"Threaded Process Managers","title":"Processes.runchannel!","text":"runchannel!(manager, jobs_channel)\n\nRun a manager with one long-lived worker task per slot, pulling jobs from jobs_channel until that channel is closed and drained.\n\n\n\n\n\nrunchannel!(manager, jobs; channel_size = length(slots(manager)))\n\nRun jobs through a bounded channel. The caller task feeds the channel once, while one spawned worker task per manager slot stays online until all jobs are consumed.\n\n\n\n\n\n","category":"function"},{"location":"user/threaded_process_managers/#Processes.runchunks!","page":"Threaded Process Managers","title":"Processes.runchunks!","text":"runchunks!(manager, jobs; chunksize)\n\nDispatch jobs as vector chunks. Each chunk is one manager job, so an InlineChunkWorker processes many examples inside one spawned task.\n\n\n\n\n\nrunchunks!(manager, jobs, schedule; chunksize)\n\nDispatch jobs as chunks and run those chunks through runthreaded! with the given thread schedule. Each chunk is one manager job, and InlineChunkWorker slots execute their examples inline on the owning threaded iteration.\n\n\n\n\n\n","category":"function"},{"location":"user/threaded_process_managers/#Processes.InlineChunkWorker","page":"Threaded Process Managers","title":"Processes.InlineChunkWorker","text":"InlineChunkWorker(process)\n\nWorker wrapper for running a chunk of examples through one InlineProcess task.\n\nThe manager starts one task per chunk instead of one task per example. Recipe callbacks load each example into the inline process context, optionally reset selected state, and optionally consume the result after each inline run.\n\n\n\n\n\n","category":"type"},{"location":"user/threaded_process_managers/#Processes.OnDemandWorkers","page":"Threaded Process Managers","title":"Processes.OnDemandWorkers","text":"OnDemandWorkers(; destroy_after_finalize = true)\n\nConstruct a fresh worker for each job by calling makeworker(idx, manager, job).\n\nWhen destroy_after_finalize is true, the worker is cleaned up after consume! and release!. Recipe destroyworker! gets first chance to clean up; if it is missing, the manager tries recipe close!, then the default worker close behavior.\n\n\n\n\n\n","category":"type"},{"location":"user/threaded_process_managers/#Processes.resetworker!","page":"Threaded Process Managers","title":"Processes.resetworker!","text":"resetworker!(slot)\n\nReset slot.worker by calling reset!(slot.worker) and return slot.\n\nFor a Process, this performs these exact mutations:\n\nslot.worker.loopidx = 1\nslot.worker.tickidx = 1\nslot.worker.paused = false\nslot.worker.shouldrun = true\nslot.worker.starttime = nothing\nslot.worker.endtime = nothing\nreset!(getalgo(slot.worker))\n\nIt does not change slot.worker.runtime_context, slot.worker.task, or slot.worker.lastresult. It also does not rebuild or clear values stored in the process context. Context fields, arrays, buffers, and refs stay exactly as they were.\n\nCall this from prepare! after you have loaded the next job into an existing context and want the next run to start from the first repeat/step again. Use reinitworker! or partialinitworker! when context values should be rebuilt through init.\n\n\n\n\n\n","category":"function"},{"location":"user/threaded_process_managers/#Processes.reinitworker!","page":"Threaded Process Managers","title":"Processes.reinitworker!","text":"reinitworker!(slot, inputs_overrides...; kwargs...)\n\nReplace the whole context of slot.worker by running the normal process init pipeline, then return slot.\n\nThis is different from resetworker!: it rebuilds context values by calling init(getalgo(slot.worker), inputs_overrides...; lifetime = lifetime(slot.worker)) and then committing the resulting persistent context back onto the worker. Use it from prepare! when a job needs freshly initialized context state instead of reusing the previous context object.\n\n\n\n\n\n","category":"function"},{"location":"user/threaded_process_managers/#Processes.partialinitworker!","page":"Threaded Process Managers","title":"Processes.partialinitworker!","text":"partialinitworker!(slot, inputs_overrides...)\n\nReinitialize only the context targets named by inputs_overrides, then return slot.\n\nThis keeps the existing process context as the starting point and runs partialinit for the affected algorithm or state entries. Use it when one part of the context should be rebuilt through its init method while the rest of the context should keep its current values. Concretely, it builds a lifecycle-wrapped algorithm from the current process context, runs partialinit(algo, inputs_overrides...), and assigns the returned context back to slot.worker.\n\n\n\n\n\n","category":"function"},{"location":"user/threaded_process_managers/#Processes.slots","page":"Threaded Process Managers","title":"Processes.slots","text":"slots(manager)\n\nReturn the manager's mutable worker slots.\n\n\n\n\n\n","category":"function"},{"location":"user/threaded_process_managers/#Processes.workers","page":"Threaded Process Managers","title":"Processes.workers","text":"workers(manager)\n\nReturn the workers stored in each manager slot.\n\n\n\n\n\n","category":"function"},{"location":"man/usage/#usage","page":"Usage Guide","title":"Usage Guide","text":"","category":"section"},{"location":"man/usage/","page":"Usage Guide","title":"Usage Guide","text":"This page is kept only as a compatibility entry point for older links.","category":"page"},{"location":"man/usage/","page":"Usage Guide","title":"Usage Guide","text":"For current documentation, use the split docs below.","category":"page"},{"location":"man/usage/#User-Documentation","page":"Usage Guide","title":"User Documentation","text":"","category":"section"},{"location":"man/usage/","page":"Usage Guide","title":"Usage Guide","text":"Algorithms and States\nReferencing Algorithms\nContexts and Indexing\nRoutes and Shares\nInit, Overrides, and Runtime Inputs\nVars (Var Selectors)\nLifetime\nRunning, Wait, Fetch\nCopying Processes\nThreaded Process Managers\nValue Semantics and Unique","category":"page"},{"location":"man/usage/#Internals","page":"Usage Guide","title":"Internals","text":"","category":"section"},{"location":"man/usage/","page":"Usage Guide","title":"Usage Guide","text":"Registry Internals\nContext Internals\nRoutes and Shares Internals\nProcess Pipeline Internals","category":"page"},{"location":"internals/contexts/#context_internals","page":"Contexts","title":"Context Internals","text":"","category":"section"},{"location":"internals/contexts/","page":"Contexts","title":"Contexts","text":"The runtime data stack is:","category":"page"},{"location":"internals/contexts/","page":"Contexts","title":"Contexts","text":"ProcessContext\nSubContext\nSubContextView","category":"page"},{"location":"internals/contexts/#1.-ProcessContext","page":"Contexts","title":"1. ProcessContext","text":"","category":"section"},{"location":"internals/contexts/","page":"Contexts","title":"Contexts","text":"ProcessContext{D,Reg} holds (src/Context/StructDefs.jl):","category":"page"},{"location":"internals/contexts/","page":"Contexts","title":"Contexts","text":"subcontexts::D: named tuple of subcontexts plus globals.\nregistry::Reg: a NameSpaceRegistry used for static routing and lookup.","category":"page"},{"location":"internals/contexts/","page":"Contexts","title":"Contexts","text":"Access patterns (src/Context/ProcessContexts.jl):","category":"page"},{"location":"internals/contexts/","page":"Contexts","title":"Contexts","text":"pc[:name] or pc.name by subcontext symbol.\npc[obj] by algorithm/state value/type (resolved through registry key).","category":"page"},{"location":"internals/contexts/","page":"Contexts","title":"Contexts","text":"globals is a regular field in subcontexts; runtime code injects process-level values there (like process, lifetime, algo).","category":"page"},{"location":"internals/contexts/#2.-SubContext","page":"Contexts","title":"2. SubContext","text":"","category":"section"},{"location":"internals/contexts/","page":"Contexts","title":"Contexts","text":"SubContext{Name,Data} stores (src/Context/StructDefs.jl):","category":"page"},{"location":"internals/contexts/","page":"Contexts","title":"Contexts","text":"data::NamedTuple: local variables owned by that entity.","category":"page"},{"location":"internals/contexts/","page":"Contexts","title":"Contexts","text":"Initialization builds empty SubContexts for every registry key, then fills them by init.","category":"page"},{"location":"internals/contexts/","page":"Contexts","title":"Contexts","text":"Route/share metadata is deliberately not stored on SubContext. Plan routing is resolved into step-local StepRouting values and attached to SubContextView types while a child runs. This keeps persistent context shape independent from execution-plan wiring.","category":"page"},{"location":"internals/contexts/#3.-SubContextView","page":"Contexts","title":"3. SubContextView","text":"","category":"section"},{"location":"internals/contexts/","page":"Contexts","title":"Contexts","text":"step!, init, and cleanup run against a SubContextView (src/Context/View/StructDef.jl).","category":"page"},{"location":"internals/contexts/","page":"Contexts","title":"Contexts","text":"A view carries:","category":"page"},{"location":"internals/contexts/","page":"Contexts","title":"Contexts","text":"the full context,\nthe current identifiable instance,\noptionally injected locals.\nroute/share metadata for the current step, as type parameters.","category":"page"},{"location":"internals/contexts/","page":"Contexts","title":"Contexts","text":"Property access is generated through VarLocations (src/Context/View/Locations.jl):","category":"page"},{"location":"internals/contexts/","page":"Contexts","title":"Contexts","text":"local vars,\nshared-context vars from the current step routing,\nrouted vars from the current step routing,\ninjected vars.","category":"page"},{"location":"internals/contexts/","page":"Contexts","title":"Contexts","text":"Name precedence for reads is determined by NamedTuple merge order. Later groups override earlier groups:","category":"page"},{"location":"internals/contexts/","page":"Contexts","title":"Contexts","text":"injected vars\nlocal vars\nrouted vars\nshared vars","category":"page"},{"location":"internals/contexts/","page":"Contexts","title":"Contexts","text":"This means local and injected names override route/share names on collisions.","category":"page"},{"location":"internals/contexts/#4.-Merging-and-Replacing","page":"Contexts","title":"4. Merging and Replacing","text":"","category":"section"},{"location":"internals/contexts/","page":"Contexts","title":"Contexts","text":"merge(view, namedtuple) (src/GeneratedCode/SubContextView.jl) maps return names back to concrete target subcontexts and variables.","category":"page"},{"location":"internals/contexts/","page":"Contexts","title":"Contexts","text":"Existing mapped variable: update that mapped target.\nUnknown variable: added to the current local subcontext.","category":"page"},{"location":"internals/contexts/","page":"Contexts","title":"Contexts","text":"replace(view, (;SubKey => nt)) replaces the full subcontext and is used during init.","category":"page"},{"location":"internals/contexts/","page":"Contexts","title":"Contexts","text":"merge_into_subcontexts (src/Context/ProcessContexts.jl) enforces that subcontext structure remains valid.","category":"page"},{"location":"internals/contexts/","page":"Contexts","title":"Contexts","text":"A type-change guard in generated merge asserts the new ProcessContext type stays identical, preventing accidental type instability.","category":"page"},{"location":"user/algorithms_states/#algorithms_states_user","page":"Algorithms and States","title":"Algorithms and States","text":"","category":"section"},{"location":"user/algorithms_states/","page":"Algorithms and States","title":"Algorithms and States","text":"ProcessAlgorithm and ProcessState are the two main building blocks you compose into a process.","category":"page"},{"location":"user/algorithms_states/","page":"Algorithms and States","title":"Algorithms and States","text":"Use ProcessAlgorithm for something that actively participates in the loop by implementing Processes.step!.\nUse ProcessState for data that should be initialized into a subcontext and then shared or read by algorithms.","category":"page"},{"location":"user/algorithms_states/","page":"Algorithms and States","title":"Algorithms and States","text":"Both are process entities: values that the package knows how to place inside a process. When a process is prepared, each entity gets a named part of the process context. That named part is its subcontext.","category":"page"},{"location":"user/algorithms_states/","page":"Algorithms and States","title":"Algorithms and States","text":"User methods receive a view of the current subcontext, plus any routed or shared values that were made visible to it. In normal code, treat that view like a read-only input object. Return a NamedTuple to write values back.","category":"page"},{"location":"user/algorithms_states/#Lifecycle-Hooks","page":"Algorithms and States","title":"Lifecycle Hooks","text":"","category":"section"},{"location":"user/algorithms_states/","page":"Algorithms and States","title":"Algorithms and States","text":"The framework lifecycle is:","category":"page"},{"location":"user/algorithms_states/","page":"Algorithms and States","title":"Algorithms and States","text":"init phase\nlooped step! phase\ncleanup phase","category":"page"},{"location":"user/algorithms_states/","page":"Algorithms and States","title":"Algorithms and States","text":"Order matters here: states are initialized first, then algorithms. Cleanup follows the same order. This means an algorithm can read values prepared by an earlier state if those values are routed or shared to it.","category":"page"},{"location":"user/algorithms_states/","page":"Algorithms and States","title":"Algorithms and States","text":"Two details from the implementation are worth knowing:","category":"page"},{"location":"user/algorithms_states/","page":"Algorithms and States","title":"Algorithms and States","text":"cleanup runs on natural finite completion.\nIf a process is interrupted, paused, or runs under Indefinite(), the current context is stored without automatic cleanup.","category":"page"},{"location":"user/algorithms_states/","page":"Algorithms and States","title":"Algorithms and States","text":"There is no built-in prepare! hook in the current pipeline. If you want a one-time preparation step, fold it into init or guard the first step! with a flag in state.","category":"page"},{"location":"user/algorithms_states/#Full-Definitions","page":"Algorithms and States","title":"Full Definitions","text":"","category":"section"},{"location":"user/algorithms_states/","page":"Algorithms and States","title":"Algorithms and States","text":"struct MyAlgo <: ProcessAlgorithm\n    gain::Float64\nend\n\nfunction Processes.init(a::MyAlgo, context)\n    x = 0.0\n    return (; x)\nend\n\nfunction Processes.step!(a::MyAlgo, context)\n    (; x) = context\n    x = x + a.gain\n    return (; x)\nend\n\nfunction Processes.cleanup(::MyAlgo, context)\n    return (;)\nend","category":"page"},{"location":"user/algorithms_states/","page":"Algorithms and States","title":"Algorithms and States","text":"struct MyState <: ProcessState end\n\nfunction Processes.init(::MyState, context)\n    return (; shared_buffer = Float64[])\nend","category":"page"},{"location":"user/algorithms_states/#Macro-Shortcuts","page":"Algorithms and States","title":"Macro Shortcuts","text":"","category":"section"},{"location":"user/algorithms_states/#@ProcessAlgorithm","page":"Algorithms and States","title":"@ProcessAlgorithm","text":"","category":"section"},{"location":"user/algorithms_states/","page":"Algorithms and States","title":"Algorithms and States","text":"@ProcessAlgorithm creates the struct and the needed step! methods from a function signature.","category":"page"},{"location":"user/algorithms_states/","page":"Algorithms and States","title":"Algorithms and States","text":"@ProcessAlgorithm function Accumulate(x, gain)\n    x = x + gain\n    return (; x)\nend","category":"page"},{"location":"user/algorithms_states/","page":"Algorithms and States","title":"Algorithms and States","text":"You can still define init and cleanup manually for the generated type.","category":"page"},{"location":"user/algorithms_states/#Macro-Generated-Algorithm-Semantics","page":"Algorithms and States","title":"Macro-Generated Algorithm Semantics","text":"","category":"section"},{"location":"user/algorithms_states/","page":"Algorithms and States","title":"Algorithms and States","text":"@ProcessAlgorithm also supports managed local state and configuration fields. Managed local state is data that belongs to one algorithm and is created during init, then read again during each step!.","category":"page"},{"location":"user/algorithms_states/","page":"Algorithms and States","title":"Algorithms and States","text":"The signature is split into:","category":"page"},{"location":"user/algorithms_states/","page":"Algorithms and States","title":"Algorithms and States","text":"plain positional arguments: values read from context during Processes.step!\n@managed(...) positional arguments: algorithm-owned values created during Processes.init\nnormal keyword arguments: values read from context during Processes.step!, using the declared default when absent\noptional trailing @input((; ...)) / @inputs((; ...)) / @init((; ...)): values read only while constructing managed state\noptional @config ... declarations before the function: fields stored on the generated algorithm object","category":"page"},{"location":"user/algorithms_states/","page":"Algorithms and States","title":"Algorithms and States","text":"Example:","category":"page"},{"location":"user/algorithms_states/","page":"Algorithms and States","title":"Algorithms and States","text":"@ProcessAlgorithm begin\n    @config n::Int = 8\n    @config damp = 1.0\n\n    function MyAlgo(\n        signal,\n        @managed(buffer = zeros(n)),\n        @managed(scale),\n        @managed(metric = 0.0);\n        @inputs((; scale = 2.0))\n    )\n        @inbounds for i in eachindex(signal)\n            buffer[i] = damp * scale * signal[i]\n        end\n        metric = sum(buffer)\n        return (; buffer, scale, metric)\n    end\nend","category":"page"},{"location":"user/algorithms_states/","page":"Algorithms and States","title":"Algorithms and States","text":"Rules worth knowing:","category":"page"},{"location":"user/algorithms_states/","page":"Algorithms and States","title":"Algorithms and States","text":"@managed(name) captures name from the init context into local managed state.\n@managed(name = expr) evaluates expr during Processes.init.\n@managed(a, b = expr, c = expr2) expands to multiple managed locals in order.\n@input/@inputs/@init may only appear once and must be the last keyword-like item.\n@config fields must have defaults and become fields on the generated struct. You can write them in a surrounding block or as a prelude like @ProcessAlgorithm @config seed = 1 function MyAlgo(...) ... end.\ninside the algorithm body, config fields are available directly by name. Use seed, not config.seed.\nplain positional arguments are runtime-only and are not available while constructing managed state.\nJulia where signatures are supported.","category":"page"},{"location":"user/algorithms_states/","page":"Algorithms and States","title":"Algorithms and States","text":"For a macro-generated algorithm MyAlgo, the main entrypoints are:","category":"page"},{"location":"user/algorithms_states/","page":"Algorithms and States","title":"Algorithms and States","text":"direct/bootstrap call: step!(MyAlgo(), args...; @inputs((; ...)))\ninit hook: Processes.init(MyAlgo(), context)\nstep hook: Processes.step!(MyAlgo(), context)","category":"page"},{"location":"user/algorithms_states/","page":"Algorithms and States","title":"Algorithms and States","text":"Internally the macro defines:","category":"page"},{"location":"user/algorithms_states/","page":"Algorithms and States","title":"Algorithms and States","text":"struct MyAlgo <: ProcessAlgorithm end or Base.@kwdef struct MyAlgo ... end\na hidden implementation function containing the user body\npublic Processes.step!(algo::MyAlgo, ...) methods for direct calls\ngenerated Processes.init and Processes.step! methods that feed the implementation","category":"page"},{"location":"user/algorithms_states/","page":"Algorithms and States","title":"Algorithms and States","text":"Type annotations and where clauses are preserved on the generated public call signatures and the hidden implementation function. The runtime context extraction methods currently bind simple locals before forwarding into that typed implementation.","category":"page"},{"location":"user/algorithms_states/#Analysis-Friendly-Forms","page":"Algorithms and States","title":"Analysis-Friendly Forms","text":"","category":"section"},{"location":"user/algorithms_states/","page":"Algorithms and States","title":"Algorithms and States","text":"If you want ContextAnalyser to discover dependencies more reliably:","category":"page"},{"location":"user/algorithms_states/","page":"Algorithms and States","title":"Algorithms and States","text":"use @inputs((; ...)) to make init-time requirements explicit\nuse context.name or (; name) = context for required reads\nuse get(context, :name, default) for optional reads\nreturn plain NamedTuples from init and step!","category":"page"},{"location":"user/algorithms_states/","page":"Algorithms and States","title":"Algorithms and States","text":"See Init Analysis for the analyzer workflow and limitations.","category":"page"},{"location":"user/algorithms_states/#@ProcessState","page":"Algorithms and States","title":"@ProcessState","text":"","category":"section"},{"location":"user/algorithms_states/","page":"Algorithms and States","title":"Algorithms and States","text":"@ProcessState creates a ProcessState and an init method.","category":"page"},{"location":"user/algorithms_states/","page":"Algorithms and States","title":"Algorithms and States","text":"@ProcessState function SharedParams(dt)\n    return (; dt)\nend","category":"page"},{"location":"user/algorithms_states/#Composition","page":"Algorithms and States","title":"Composition","text":"","category":"section"},{"location":"user/algorithms_states/","page":"Algorithms and States","title":"Algorithms and States","text":"Compose entities with loop algorithms:","category":"page"},{"location":"user/algorithms_states/","page":"Algorithms and States","title":"Algorithms and States","text":"CompositeAlgorithm(...) for interleaved stepping with intervals.\nRoutine(...) for sequential blocks with repeats.","category":"page"},{"location":"user/algorithms_states/","page":"Algorithms and States","title":"Algorithms and States","text":"Both can include ProcessStates and user options such as Route and Share.","category":"page"},{"location":"user/algorithms_states/#Changing-a-Loop-Algorithm-Schedule","page":"Algorithms and States","title":"Changing a Loop Algorithm Schedule","text":"","category":"section"},{"location":"user/algorithms_states/","page":"Algorithms and States","title":"Algorithms and States","text":"Process lifetime controls how long the outer process loop runs. Inside a loop algorithm, the per-child schedule is controlled by the loop algorithm itself:","category":"page"},{"location":"user/algorithms_states/","page":"Algorithms and States","title":"Algorithms and States","text":"CompositeAlgorithm and ThreadedCompositeAlgorithm use intervals.\nRoutine uses repeats.","category":"page"},{"location":"user/algorithms_states/","page":"Algorithms and States","title":"Algorithms and States","text":"For composite algorithms, use the edit helpers before resolving the algorithm:","category":"page"},{"location":"user/algorithms_states/","page":"Algorithms and States","title":"Algorithms and States","text":"algo = CompositeAlgorithm(FastStep, SlowStep, (1, 10))\n\nalgo = changeinterval(algo, 2, 20)\ninterval(algo, 2) == Processes.Interval(20)\n\nalgo = changeintervals(algo, (1, 5))\nintervals(algo) == (Processes.Interval(1), Processes.Interval(5))","category":"page"},{"location":"user/algorithms_states/","page":"Algorithms and States","title":"Algorithms and States","text":"These helpers return a new loop algorithm with the updated schedule. They are intended for unresolved loop algorithms; if you already called resolve, edit the original algorithm and resolve it again.","category":"page"},{"location":"user/algorithms_states/","page":"Algorithms and States","title":"Algorithms and States","text":"When adding a child, pass the new child's schedule as the last argument:","category":"page"},{"location":"user/algorithms_states/","page":"Algorithms and States","title":"Algorithms and States","text":"algo = addalgo(algo, :logger => Logger, 100)","category":"page"},{"location":"user/algorithms_states/","page":"Algorithms and States","title":"Algorithms and States","text":"For Routine, the constructor and addalgo schedule argument are repeat counts:","category":"page"},{"location":"user/algorithms_states/","page":"Algorithms and States","title":"Algorithms and States","text":"routine = Routine(Prepare, Train, (1, 50))\nroutine = addalgo(routine, :validate => Validate, 1)","category":"page"},{"location":"#Processes.jl","page":"Home","title":"Processes.jl","text":"","category":"section"},{"location":"","page":"Home","title":"Home","text":"Processes.jl helps you build Julia loops from small named pieces.","category":"page"},{"location":"","page":"Home","title":"Home","text":"An algorithm is a piece of loop code. It is a subtype of ProcessAlgorithm and usually defines Processes.step!.","category":"page"},{"location":"","page":"Home","title":"Home","text":"A state is a piece of setup data. It is a subtype of ProcessState and usually defines Processes.init.","category":"page"},{"location":"","page":"Home","title":"Home","text":"A process combines algorithms, states, inputs, and stop rules into a running loop. While it runs, values live in a context. Each algorithm or state gets its own named part of that context, called a subcontext.","category":"page"},{"location":"","page":"Home","title":"Home","text":"The package keeps context shapes stable after setup, so tight loops can stay fast while still letting you compose larger workflows.","category":"page"},{"location":"","page":"Home","title":"Home","text":"Start with the user documentation if you want to build processes with the package. The internals section is for understanding how registries, contexts, routing, and generated loops are implemented.","category":"page"},{"location":"","page":"Home","title":"Home","text":"If you are new to the package, read these first:","category":"page"},{"location":"","page":"Home","title":"Home","text":"Algorithms and States\nRunning, Wait, Fetch\nContexts and Indexing\nInit, Overrides, and Runtime Inputs\nRoutes and Shares\nComposite DSL","category":"page"},{"location":"#User-Documentation","page":"Home","title":"User Documentation","text":"","category":"section"},{"location":"","page":"Home","title":"Home","text":"Algorithms and States\nComposite DSL\nReferencing Algorithms\nContexts and Indexing\nInit Analysis\nRoutes and Shares\nInit, Overrides, and Runtime Inputs\nVars (Var Selectors)\nLifetime\nRunning, Wait, Fetch\nCopying Processes\nThreaded Process Managers\nValue Semantics and Unique","category":"page"},{"location":"#Internals","page":"Home","title":"Internals","text":"","category":"section"},{"location":"","page":"Home","title":"Home","text":"Registry Internals\nContext Internals\nRoutes and Shares Internals\nProcess Pipeline Internals","category":"page"},{"location":"user/lifetime/#lifetime_user","page":"Lifetime","title":"Lifetime","text":"","category":"section"},{"location":"user/lifetime/","page":"Lifetime","title":"Lifetime","text":"lifetime controls when a process loop stops.","category":"page"},{"location":"user/lifetime/#Most-Common-Usage","page":"Lifetime","title":"Most Common Usage","text":"","category":"section"},{"location":"user/lifetime/#Fixed-number-of-iterations","page":"Lifetime","title":"Fixed number of iterations","text":"","category":"section"},{"location":"user/lifetime/","page":"Lifetime","title":"Lifetime","text":"p = Process(algo; repeats = 1_000)","category":"page"},{"location":"user/lifetime/","page":"Lifetime","title":"Lifetime","text":"The repeats keyword is converted internally to Repeat(1000).","category":"page"},{"location":"user/lifetime/","page":"Lifetime","title":"Lifetime","text":"You can also pass the lifetime object explicitly:","category":"page"},{"location":"user/lifetime/","page":"Lifetime","title":"Lifetime","text":"p = Process(algo; lifetime = Repeat(1_000))","category":"page"},{"location":"user/lifetime/","page":"Lifetime","title":"Lifetime","text":"For Process, the lifetime keyword is reserved for Lifetime objects. Use repeats = ... for plain integer counts.","category":"page"},{"location":"user/lifetime/#Default-behavior","page":"Lifetime","title":"Default behavior","text":"","category":"section"},{"location":"user/lifetime/","page":"Lifetime","title":"Lifetime","text":"If you do not pass lifetime:","category":"page"},{"location":"user/lifetime/","page":"Lifetime","title":"Lifetime","text":"most processes default to Indefinite()\nRoutine defaults to one pass (Repeat(1)) when lifetime = nothing","category":"page"},{"location":"user/lifetime/#Explicit-Lifetime-Types","page":"Lifetime","title":"Explicit Lifetime Types","text":"","category":"section"},{"location":"user/lifetime/","page":"Lifetime","title":"Lifetime","text":"These types are available in code:","category":"page"},{"location":"user/lifetime/","page":"Lifetime","title":"Lifetime","text":"Repeat(n)\nIndefinite()\nUntil(condition, selector)\nRepeatOrUntil(condition, n, selector)","category":"page"},{"location":"user/lifetime/","page":"Lifetime","title":"Lifetime","text":"The exported AtLeast and AtLeastAtMost lifetime types are also available for less common \"minimum count plus condition\" rules.","category":"page"},{"location":"user/lifetime/#Changing-Lifetime","page":"Lifetime","title":"Changing Lifetime","text":"","category":"section"},{"location":"user/lifetime/","page":"Lifetime","title":"Lifetime","text":"Set the process lifetime when constructing the process:","category":"page"},{"location":"user/lifetime/","page":"Lifetime","title":"Lifetime","text":"p = Process(algo; lifetime = Repeat(1_000))","category":"page"},{"location":"user/lifetime/","page":"Lifetime","title":"Lifetime","text":"For an existing process, build a fresh process from the same task description with a different lifetime:","category":"page"},{"location":"user/lifetime/","page":"Lifetime","title":"Lifetime","text":"p2 = copyprocess(p; lifetime = Repeat(2_000))","category":"page"},{"location":"user/lifetime/","page":"Lifetime","title":"Lifetime","text":"This changes the outer process lifetime. It does not change how often child loop algorithms run inside a CompositeAlgorithm or Routine. Those schedules are loop-algorithm settings: use changeinterval, changeintervals, or the schedule argument to addalgo. See Algorithms and States.","category":"page"},{"location":"user/lifetime/#Until:-Stop-on-a-Condition","page":"Lifetime","title":"Until: Stop on a Condition","text":"","category":"section"},{"location":"user/lifetime/","page":"Lifetime","title":"Lifetime","text":"Until checks a value from context each loop.   Here, condition(value) is a stop condition:","category":"page"},{"location":"user/lifetime/","page":"Lifetime","title":"Lifetime","text":"true -> stop now\nfalse -> continue","category":"page"},{"location":"user/lifetime/","page":"Lifetime","title":"Lifetime","text":"A practical pattern is to use Var(...) as selector:","category":"page"},{"location":"user/lifetime/","page":"Lifetime","title":"Lifetime","text":"counter = Counter()\n\np = Process(\n    counter;\n    lifetime = Until(\n        x -> x >= 100,\n        Var(counter, :count),\n    ),\n)","category":"page"},{"location":"user/lifetime/#RepeatOrUntil:-Max-Iterations-Or-Condition","page":"Lifetime","title":"RepeatOrUntil: Max Iterations Or Condition","text":"","category":"section"},{"location":"user/lifetime/","page":"Lifetime","title":"Lifetime","text":"RepeatOrUntil combines:","category":"page"},{"location":"user/lifetime/","page":"Lifetime","title":"Lifetime","text":"a maximum number of iterations (n)\na stop condition like Until","category":"page"},{"location":"user/lifetime/","page":"Lifetime","title":"Lifetime","text":"The loop stops at whichever happens first:","category":"page"},{"location":"user/lifetime/","page":"Lifetime","title":"Lifetime","text":"repeat count reaches n, or\ncondition becomes true.","category":"page"},{"location":"user/lifetime/","page":"Lifetime","title":"Lifetime","text":"Example:","category":"page"},{"location":"user/lifetime/","page":"Lifetime","title":"Lifetime","text":"counter = Counter()\n\np = Process(\n    counter;\n    lifetime = RepeatOrUntil(\n        x -> x >= 100,   # stop condition\n        1_000,           # hard max iterations\n        Var(counter, :count),\n    ),\n)","category":"page"},{"location":"user/lifetime/","page":"Lifetime","title":"Lifetime","text":"Important:","category":"page"},{"location":"user/lifetime/","page":"Lifetime","title":"Lifetime","text":"Use the same algorithm reference you used in Process(...) (same instance or same Unique variable).\nVar(:name) reads from globals (for example Var(:process)).\nThe safest current Until usage is a single selector value.","category":"page"},{"location":"user/lifetime/","page":"Lifetime","title":"Lifetime","text":"For full Var details, see Vars (Var Selectors).","category":"page"},{"location":"user/lifetime/#Notes","page":"Lifetime","title":"Notes","text":"","category":"section"},{"location":"user/lifetime/","page":"Lifetime","title":"Lifetime","text":"The lifetime types are exported, so Repeat(10) and Processes.Repeat(10) both work after using Processes.\nManual stop and pause still work regardless of lifetime.","category":"page"},{"location":"user/routes_shares/#routes_shares_user","page":"Routes and Shares","title":"Routes and Shares","text":"","category":"section"},{"location":"user/routes_shares/","page":"Routes and Shares","title":"Routes and Shares","text":"Route and Share make values from one algorithm or state visible to another.","category":"page"},{"location":"user/routes_shares/","page":"Routes and Shares","title":"Routes and Shares","text":"Each algorithm or state owns a subcontext: its named part of the full process context. A route exposes selected names from one subcontext. A share exposes all names from one subcontext.","category":"page"},{"location":"user/routes_shares/#Referencing-Algorithms","page":"Routes and Shares","title":"Referencing Algorithms","text":"","category":"section"},{"location":"user/routes_shares/","page":"Routes and Shares","title":"Routes and Shares","text":"Recap:","category":"page"},{"location":"user/routes_shares/","page":"Routes and Shares","title":"Routes and Shares","text":"Use the same reference style you used in composition (type, saved instance, or saved Unique variable).\nDo not target with a fresh object unless that exact object was inserted in the composition.","category":"page"},{"location":"user/routes_shares/","page":"Routes and Shares","title":"Routes and Shares","text":"For full examples, see Referencing Algorithms.","category":"page"},{"location":"user/routes_shares/#Route:-Specific-Variables","page":"Routes and Shares","title":"Route: Specific Variables","text":"","category":"section"},{"location":"user/routes_shares/","page":"Routes and Shares","title":"Routes and Shares","text":"Route selected variables from source to target, optionally aliased:","category":"page"},{"location":"user/routes_shares/","page":"Routes and Shares","title":"Routes and Shares","text":"CompositeAlgorithm(\n    Source, Target,\n    (1, 1),\n    Route(Source => Target, :value => :input_value),\n)","category":"page"},{"location":"user/routes_shares/","page":"Routes and Shares","title":"Routes and Shares","text":"Target sees context.input_value.","category":"page"},{"location":"user/routes_shares/","page":"Routes and Shares","title":"Routes and Shares","text":"If no alias is given, the target sees the same name as the source.","category":"page"},{"location":"user/routes_shares/#Transform-Route-Values","page":"Routes and Shares","title":"Transform Route Values","text":"","category":"section"},{"location":"user/routes_shares/","page":"Routes and Shares","title":"Routes and Shares","text":"You can provide transform = f (single mapping route) to expose transformed source values:","category":"page"},{"location":"user/routes_shares/","page":"Routes and Shares","title":"Routes and Shares","text":"Route(Source => Target, :series => :latest, transform = x -> x[end])","category":"page"},{"location":"user/routes_shares/","page":"Routes and Shares","title":"Routes and Shares","text":"If the target may return the routed alias and you want that return written back through the transformed route, provide reverse_transform = g:","category":"page"},{"location":"user/routes_shares/","page":"Routes and Shares","title":"Routes and Shares","text":"Route(\n    Source => Target,\n    :value => :input,\n    transform = x -> 2x,\n    reverse_transform = y -> y / 2,\n)","category":"page"},{"location":"user/routes_shares/","page":"Routes and Shares","title":"Routes and Shares","text":"In this example, Target reads context.input == 2 * Source.value. If Target returns (; input = new_input), Source.value is updated with new_input / 2.","category":"page"},{"location":"user/routes_shares/#Transform-From-Multiple-Source-Variables","page":"Routes and Shares","title":"Transform From Multiple Source Variables","text":"","category":"section"},{"location":"user/routes_shares/","page":"Routes and Shares","title":"Routes and Shares","text":"A transform route can also read multiple source variables by using a tuple on the left-hand side:","category":"page"},{"location":"user/routes_shares/","page":"Routes and Shares","title":"Routes and Shares","text":"Route(\n    Source => Target,\n    (:x, :y) => :norm_xy,\n    transform = (x, y) -> sqrt(x^2 + y^2),\n    reverse_transform = norm_xy -> (; x = norm_xy, y = 0.0),\n)","category":"page"},{"location":"user/routes_shares/","page":"Routes and Shares","title":"Routes and Shares","text":"Important constraints from the current implementation:","category":"page"},{"location":"user/routes_shares/","page":"Routes and Shares","title":"Routes and Shares","text":"If transform or reverse_transform is provided, the route must define exactly one mapping.\nMulti-source reverse transforms may return a tuple in source-variable order or a named tuple keyed by source variable name.\nReturning a transformed route alias without reverse_transform is an error, because the writeback would otherwise be ambiguous.","category":"page"},{"location":"user/routes_shares/#Share:-Whole-Subcontext","page":"Routes and Shares","title":"Share: Whole Subcontext","text":"","category":"section"},{"location":"user/routes_shares/","page":"Routes and Shares","title":"Routes and Shares","text":"Expose all source variables to target:","category":"page"},{"location":"user/routes_shares/","page":"Routes and Shares","title":"Routes and Shares","text":"Share(Source, Target)","category":"page"},{"location":"user/routes_shares/","page":"Routes and Shares","title":"Routes and Shares","text":"Default is bidirectional (directional = false), so both sides can read the other side's values. Use directional = true for a one-way share from the first argument to the second.","category":"page"},{"location":"user/routes_shares/#Read-and-Write-Semantics","page":"Routes and Shares","title":"Read and Write Semantics","text":"","category":"section"},{"location":"user/routes_shares/","page":"Routes and Shares","title":"Routes and Shares","text":"Routed and shared names point back to stored values. If the target returns one of those names from step!, the source subcontext can be updated.","category":"page"},{"location":"user/routes_shares/","page":"Routes and Shares","title":"Routes and Shares","text":"This enables coupling patterns like:","category":"page"},{"location":"user/routes_shares/","page":"Routes and Shares","title":"Routes and Shares","text":"algorithm B reading and damping algorithm A's velocity, then returning updated velocity.","category":"page"},{"location":"user/routes_shares/#Plan-Local-Routes","page":"Routes and Shares","title":"Plan-Local Routes","text":"","category":"section"},{"location":"user/routes_shares/","page":"Routes and Shares","title":"Routes and Shares","text":"Routes belong to the plan node where they are declared. In the DSL, a route statement inside a composite/routine is attached to that local child step, so the same algorithm type can be reused elsewhere with different local wiring.","category":"page"},{"location":"user/routes_shares/","page":"Routes and Shares","title":"Routes and Shares","text":"Example:","category":"page"},{"location":"user/routes_shares/","page":"Routes and Shares","title":"Routes and Shares","text":"@CompositeAlgorithm begin\n    c1 = @CompositeAlgorithm begin\n        inner = Source()\n    end\n    sink = Sink()\n    @route c1.inner.value => sink.value\nend","category":"page"},{"location":"user/routes_shares/","page":"Routes and Shares","title":"Routes and Shares","text":"If a local route and a broader route expose the same target alias, the local route takes precedence for that child step.","category":"page"}]
}
